--
-- Name: proc_bio_data(); Type: PROCEDURE; Schema: expanded_radet; Owner: lamisplus_etl
--

CREATE PROCEDURE expanded_radet.proc_bio_data()
    LANGUAGE plpgsql
    AS $$
DECLARE start_time TIMESTAMP;
DECLARE end_time TIMESTAMP;
BEGIN

SELECT TIMEOFDAY() INTO start_time;

drop table if exists expanded_radet.cte_bio_data_new;
create table expanded_radet.cte_bio_data_new AS
SELECT *,EXTRACT(YEAR from AGE((select date from expanded_radet.period where is_active),  dateofbirth)) as age
FROM expanded_radet.patient_bio_data
WHERE ods_hiv_enrollment_person_uuid IS NOT NULL
AND ods_hiv_art_clinical_person_uuid IS NOT NULL
AND regimenAtStart IS NOT NULL
AND ods_hiv_art_clinical_archived = 0
AND ods_hiv_enrollment_archived = 0
AND is_commencement = TRUE
AND visit_date >= '1980-01-01'
AND visit_date <= (select date from expanded_radet.period where is_active);

drop table if exists expanded_radet.cte_bio_data;
alter table expanded_radet.cte_bio_data_new rename to cte_bio_data;

create index unq_personuuid_datim_ctebiodata 
on expanded_radet.cte_bio_data(personuuid,bio_ods_datim_id);

SELECT TIMEOFDAY() INTO end_time;
INSERT INTO expanded_radet.expanded_radet_monitoring (table_name, start_time,end_time) 
VALUES ('bio_data', start_time,end_time);

END
$$;


ALTER PROCEDURE expanded_radet.proc_bio_data() OWNER TO lamisplus_etl;

--
-- Name: proc_biometric(); Type: PROCEDURE; Schema: expanded_radet; Owner: lamisplus_etl
--

CREATE PROCEDURE expanded_radet.proc_biometric()
    LANGUAGE plpgsql
    AS $$DECLARE start_time TIMESTAMP;
DECLARE end_time TIMESTAMP;
BEGIN

SELECT TIMEOFDAY() INTO start_time;

DROP TABLE if exists expanded_radet.cte_biometric_new;

CREATE TABLE expanded_radet.cte_biometric_new AS
SELECT DISTINCT ON (he.person_uuid, he.ods_datim_id) he.person_uuid AS person_uuid60,
		he.ods_datim_id as biome_ods_datim_id, 
		base_count.enrollment_date AS dateBiometricsEnrolled, 
		  base_count.count AS numberOfFingersCaptured,
		  cast(recapture_count.recapture_date as date) AS dateBiometricsRecaptured,
		  recapture_count.count AS numberOfFingersRecaptured,
		  he.biometric_status AS biometricStatus, 
		  he.status_date
FROM (
SELECT * FROM dblink('db_link_ods',
'SELECT ohe.person_uuid, ohe.ods_datim_id, ohe.archived,bst.status_date, bst.biometric_status
FROM ods_hiv_enrollment ohe
LEFT JOIN (SELECT DISTINCT ON (person_id, ods_datim_id) person_id, ods_datim_id, biometric_status,
			MAX(status_date) OVER (PARTITION BY person_id, ods_datim_id  ORDER BY status_date DESC) AS status_date 
			FROM ods_hiv_status_tracker 
            WHERE archived=0) bst ON bst.person_id = ohe.person_uuid AND bst.ods_datim_id = ohe.ods_datim_id 
WHERE ohe.archived = 0')
AS sm(person_uuid character varying, ods_datim_id character varying, archived integer, 
	status_date date, biometric_status character varying)) he

LEFT JOIN expanded_radet.base_biometric base_count ON base_count.person_uuid = he.person_uuid 
AND base_count.ods_datim_id = he.ods_datim_id
LEFT JOIN expanded_radet.recapture_biometric recapture_count ON recapture_count.person_uuid = he.person_uuid 
AND recapture_count.ods_datim_id=he.ods_datim_id;

drop table if exists expanded_radet.cte_biometric;
alter table expanded_radet.cte_biometric_new rename to cte_biometric;

SELECT TIMEOFDAY() INTO end_time;
INSERT INTO expanded_radet.expanded_radet_monitoring (table_name, start_time,end_time) 
VALUES ('cte_biometric', start_time,end_time);

END
$$;


ALTER PROCEDURE expanded_radet.proc_biometric() OWNER TO lamisplus_etl;

