--
-- Name: proc_create_art_commencement_vitals_refresh(); Type: PROCEDURE; Schema: expanded_radet; Owner: lamisplus_etl
--

CREATE PROCEDURE expanded_radet.proc_create_art_commencement_vitals_refresh()
    LANGUAGE plpgsql
    AS $$
DECLARE start_time TIMESTAMP;
DECLARE last_load_end_time TIMESTAMP;
DECLARE end_time TIMESTAMP;
DECLARE record_count bigint;

BEGIN

-- Fetch the last load end time
SELECT MAX(load_end_time) 
INTO last_load_end_time
FROM streaming_remote_monitoring
WHERE table_name = 'art_commencement_vitals_refresh';

-- Fetch record count from the remote database using dblink
EXECUTE FORMAT(
	'SELECT *
	 FROM dblink(''db_link_ods'',
	 ''
	 SELECT count(uuid) 
	 FROM ods_triage_vital_sign 
	 WHERE ods_load_time >= ''%L''			   
	'') 
	 AS sm(count bigint)',last_load_end_time) 
INTO record_count;

DROP TABLE IF EXISTS expanded_radet.art_commencement_vitals_refresh;

SELECT TIMEOFDAY() INTO start_time;

EXECUTE FORMAT ('CREATE TABLE expanded_radet.art_commencement_vitals_refresh AS
SELECT * from dblink(''db_link_ods'',
''SELECT DISTINCT ON (tvs.uuid, tvs.ods_datim_id) tvs.uuid, tvs.person_uuid,tvs.ods_datim_id,tvs.archived,
tvs.body_weight as baseLineWeight, tvs.height as baseLineHeight,
CONCAT(tvs.diastolic, '''' / '''', tvs.systolic) as baseLineBp, tvs.diastolic as diastolicBp,
tvs.systolic as systolicBp, clinical_stage.display as baseLineClinicalStage,
func_status.display as baseLineFunctionalStatus,
hv.description as firstRegimen, hrt.description as firstRegimenLine,
CASE WHEN hac.cd_4=0 THEN null ELSE hac.cd_4 END  AS baseLineCd4,
CASE WHEN hac.cd_4_percentage=0 THEN null ELSE hac.cd_4_percentage END AS cd4Percentage,
hac.visit_date as artStartDate
FROM (SELECT uuid, person_uuid, ods_datim_id,body_weight,height,diastolic, systolic, archived 
	 FROM ods_triage_vital_sign WHERE ods_load_time >= ''%L'') tvs
LEFT JOIN ods_hiv_art_clinical hac ON tvs.uuid=hac.vital_sign_uuid AND hac.person_uuid = tvs.person_uuid
LEFT JOIN ods_hiv_enrollment h ON hac.hiv_enrollment_uuid = h.uuid AND hac.ods_datim_id=h.ods_datim_id
LEFT JOIN ods_patient_person p ON p.uuid=h.person_uuid AND p.ods_datim_id=h.ods_datim_id
LEFT JOIN ods_hiv_regimen hv ON hv.id=hac.regimen_id AND hv.ods_datim_id=hac.ods_datim_id
LEFT JOIN ods_hiv_regimen_type hrt ON hrt.id=hac.regimen_type_id AND hrt.ods_datim_id=hac.ods_datim_id
LEFT JOIN ods_base_application_codeset clinical_stage ON clinical_stage.id=hac.clinical_stage_id AND clinical_stage.ods_datim_id=hac.ods_datim_id
LEFT JOIN ods_base_application_codeset func_status ON func_status.id=hac.functional_status_id AND func_status.ods_datim_id=hac.ods_datim_id
WHERE hac.is_commencement=true
-- AND hac.archived=0  AND h.archived=0 AND h.facility_id=1959
'')AS sm(uuid character varying,person_uuid character varying,ods_datim_id character varying(255),archived integer,
baselineweight double precision,baselineheight double precision,baselinebp text,diastolicbp double precision,
systolicbp double precision,baselineclinicalstage character varying,baselinefunctionalstatus character varying,
firstregimen character varying,firstregimenline character varying,baselinecd4 bigint,cd4percentage bigint,artstartdate date)',
last_load_end_time);

SELECT TIMEOFDAY() INTO end_time;

ALTER TABLE expanded_radet.art_commencement_vitals_refresh
ADD CONSTRAINT unq_art_commencement_vitals_refresh UNIQUE (uuid, person_uuid, ods_datim_id);

CREATE INDEX unq_artStartDate_art_commencement_vitals_refresh 
ON expanded_radet.art_commencement_vitals_refresh(artStartDate);

DELETE FROM expanded_radet.art_commencement_vitals_refresh
WHERE archived=1;

INSERT INTO public.streaming_remote_monitoring(table_name,start_time,load_end_time,record_count)
VALUES('art_commencement_vitals_refresh',start_time, end_time,record_count);

			 
END 
$$;


ALTER PROCEDURE expanded_radet.proc_create_art_commencement_vitals_refresh() OWNER TO lamisplus_etl;

--
-- Name: proc_create_arv_pharmacy(); Type: PROCEDURE; Schema: expanded_radet; Owner: lamisplus_etl
--

CREATE PROCEDURE expanded_radet.proc_create_arv_pharmacy()
    LANGUAGE plpgsql
    AS $$
DECLARE start_time TIMESTAMP;
DECLARE end_time TIMESTAMP;
DECLARE record_count bigint;
BEGIN

SELECT count(uuid) 
FROM expanded_radet.pharmacy_details_regimen
WHERE phar_details_regimen_load_time >= 
(select MAX(load_end_time) 
 FROM public.streaming_remote_monitoring
WHERE table_name = 'arv_pharmacy')
INTO record_count;

SELECT TIMEOFDAY() INTO start_time;
CREATE TABLE expanded_radet.arv_pharmacy AS
SELECT uuid, person_uuid40, pharma_ods_datim_id, dsdModel,visit_date as dateofStartofCurrentARTRegimen,
ods_hiv_regimen_description as currentARTRegimen,ods_hiv_regimen_type_description as currentRegimenLine,
p.next_appointment as nextPickupDate, 
CAST(CAST(refill_period AS INTEGER) / 30.0 AS DECIMAL(10, 1)) AS monthsOfARVRefill
FROM (SELECT uuid, person_uuid40, pharma_ods_datim_id, dsdmodel, visit_date, ods_hiv_regimen_description, 
	  ods_hiv_regimen_type_description, next_appointment, regimen_type_id, refill_period, 
	  phar_details_regimen_load_time 
	  FROM expanded_radet.pharmacy_details_regimen
	  WHERE phar_details_regimen_load_time >=
				   (select MAX(load_end_time) 
					FROM public.streaming_remote_monitoring
					WHERE table_name = 'arv_pharmacy')) p
WHERE regimen_type_id in (1, 2, 3, 4, 14) 
--AND p.archived = 0 
AND visit_date is not null
AND refill_period is not null 
AND ods_hiv_regimen_description IS NOT NULL
AND ods_hiv_regimen_type_description IS NOT NULL;

SELECT TIMEOFDAY() INTO end_time;

ALTER TABLE expanded_radet.arv_pharmacy
ADD CONSTRAINT unq_uuid_datimid_arv_pharmacy 
UNIQUE (uuid, person_uuid40, pharma_ods_datim_id);

CREATE INDEX unq_visitdate_arv_pharmacy 
ON expanded_radet.arv_pharmacy(dateofStartofCurrentARTRegimen);

INSERT INTO public.streaming_remote_monitoring(table_name,start_time,load_end_time,record_count) 
VALUES ('arv_pharmacy',start_time, end_time,record_count);
			 
END $$;


ALTER PROCEDURE expanded_radet.proc_create_arv_pharmacy() OWNER TO lamisplus_etl;

--
-- Name: proc_create_base_biometric(); Type: PROCEDURE; Schema: expanded_radet; Owner: lamisplus_etl
--

CREATE PROCEDURE expanded_radet.proc_create_base_biometric()
    LANGUAGE plpgsql
    AS $$
DECLARE start_time TIMESTAMP;
DECLARE last_load_end_time TIMESTAMP;
DECLARE end_time TIMESTAMP;
DECLARE record_count bigint;

BEGIN
-- Fetch the last load end time
SELECT MAX(load_end_time) 
INTO last_load_end_time
FROM streaming_remote_monitoring
WHERE table_name = 'base_biometric_refresh';

-- Fetch record count from the remote database using dblink
EXECUTE format(
	'SELECT *
	 FROM dblink(''db_link_ods'',
	 ''
	 SELECT count(person_uuid) 
	 FROM ods_biometric 
	 WHERE ods_load_time >= ''%L''			   
	'') 
	 AS sm(count bigint)',last_load_end_time) 
INTO record_count;

DROP TABLE IF EXISTS expanded_radet.base_biometric;

SELECT TIMEOFDAY() INTO start_time;

EXECUTE FORMAT('CREATE TABLE expanded_radet.base_biometric AS
SELECT * FROM dblink(''db_link_ods'',
''SELECT DISTINCT ON (person_uuid, ods_datim_id) person_uuid,ods_datim_id,recapture,archived,count,
			   MAX(enrollment_date) enrollment_date
FROM ods_biometric 
WHERE ods_load_time >= ''%L''
AND version_iso_20 is not null AND version_iso_20 is true 
--AND archived=0 
AND (recapture=0 or recapture is null)
GROUP BY 1,2,3,4,5'')
AS sm(person_uuid character varying,ods_datim_id character varying, 
	  recapture integer,archived integer,count bigint,enrollment_date date)',
	  last_load_end_time);

SELECT TIMEOFDAY() INTO end_time;

ALTER TABLE expanded_radet.base_biometric
ADD CONSTRAINT unq_base_biometric UNIQUE (person_uuid,ods_datim_id);

CREATE INDEX unq_basebiometric_personuuid_datimid 
ON expanded_radet.base_biometric(person_uuid, ods_datim_id);

DELETE FROM expanded_radet.base_biometric
WHERE archived=1;

INSERT INTO public.streaming_remote_monitoring(table_name,start_time,load_end_time,record_count)
VALUES('base_biometric_refresh', start_time, end_time,record_count);

			 
END 
$$;


ALTER PROCEDURE expanded_radet.proc_create_base_biometric() OWNER TO lamisplus_etl;

