CREATE PROCEDURE expanded_radet.proc_create_recapture_biometric()
    LANGUAGE plpgsql
    AS $$
DECLARE start_time TIMESTAMP;
DECLARE last_load_end_time TIMESTAMP;
DECLARE end_time TIMESTAMP;
DECLARE record_count bigint;

BEGIN
-- Fetch the last load end time
SELECT MAX(load_end_time) 
INTO last_load_end_time
FROM streaming_remote_monitoring
WHERE table_name = 'recapture_biometric_refresh';

-- Fetch record count from the remote database using dblink
EXECUTE format(
	'SELECT *
	 FROM dblink(''db_link_ods'',
	 ''
	 SELECT count(person_uuid) 
	 FROM ods_biometric 
	 WHERE ods_load_time >= ''%L''			   
	'') 
	 AS sm(count bigint)',last_load_end_time) 
INTO record_count;

DROP TABLE IF EXISTS expanded_radet.recapture_biometric;

SELECT TIMEOFDAY() INTO start_time;
EXECUTE FORMAT('CREATE TABLE expanded_radet.recapture_biometric AS
SELECT * FROM dblink(''db_link_ods'',
''SELECT DISTINCT ON (person_uuid, ods_datim_id) person_uuid,ods_datim_id,recapture,archived,count,
			   MAX(enrollment_date) recapture_date
FROM ods_biometric 
WHERE ods_load_time >= ''%L''
AND version_iso_20 is not null AND version_iso_20 is true 
--AND archived=0 
AND recapture=1
GROUP BY 1,2,3,4,5'')
AS sm(person_uuid character varying,ods_datim_id character varying, 
	  recapture integer,archived integer,count bigint,recapture_date date)',
	  last_load_end_time);

SELECT TIMEOFDAY() INTO end_time;

ALTER TABLE expanded_radet.recapture_biometric
ADD CONSTRAINT unq_recapture_biometric_new UNIQUE (person_uuid,ods_datim_id);

CREATE INDEX unq_recapturebiometric_personuuid_datimid 
ON expanded_radet.recapture_biometric(person_uuid, ods_datim_id);

DELETE FROM expanded_radet.recapture_biometric
WHERE archived=1;

INSERT INTO public.streaming_remote_monitoring(table_name,start_time,load_end_time,record_count)
VALUES('recapture_biometric_refresh', start_time, end_time,record_count);

			 
END 
$$;


ALTER PROCEDURE expanded_radet.proc_create_recapture_biometric() OWNER TO lamisplus_etl;

