--
-- Name: proc_create_sub_tvs_current_clinical_refresh(); Type: PROCEDURE; Schema: expanded_radet; Owner: lamisplus_etl
--

CREATE PROCEDURE expanded_radet.proc_create_sub_tvs_current_clinical_refresh()
    LANGUAGE plpgsql
    AS $$
DECLARE start_time TIMESTAMP;
DECLARE last_load_end_time TIMESTAMP;
DECLARE end_time TIMESTAMP;
DECLARE record_count bigint;

BEGIN

-- Fetch the last load end time
SELECT MAX(load_end_time) 
INTO last_load_end_time
FROM streaming_remote_monitoring
WHERE table_name = 'sub_tvs_current_clinical_refresh';

-- Fetch record count from the remote database using dblink
EXECUTE FORMAT(
	'SELECT *
	 FROM dblink(''db_link_ods'',
	 ''
	 SELECT count(uuid) 
	 FROM ods_triage_vital_sign 
	 WHERE ods_load_time >= ''%L''			   
	'') 
	 AS sm(count bigint)',last_load_end_time) 
INTO record_count;

SELECT TIMEOFDAY() INTO start_time;

DROP TABLE IF EXISTS expanded_radet.sub_tvs_current_clinical_refresh;

EXECUTE FORMAT ('CREATE TABLE expanded_radet.sub_tvs_current_clinical_refresh AS
SELECT * from dblink(''db_link_ods'',
''SELECT DISTINCT ON (tvs.person_uuid, tvs.ods_datim_id) tvs.person_uuid AS person_uuid10, 
tvs.ods_datim_id as clin_ods_datim_id,CAST(tvs.capture_date AS DATE) capture_date,
body_weight AS currentWeight,tbs.display AS tbStatus1, 
bac.display AS currentClinicalStage,
(CASE WHEN preg.display IS NOT NULL THEN preg.display ELSE hac.pregnancy_status END) AS pregnancyStatus, 
CASE WHEN hac.tb_screen IS NOT NULL THEN CAST(hac.visit_date AS DATE) ELSE NULL END AS dateOfTbScreened1, 
tvs_archived
FROM (SELECT uuid,person_uuid,ods_datim_id,capture_date,body_weight,archived tvs_archived
		FROM ods_triage_vital_sign WHERE ods_load_time > ''%L'') tvs 
INNER JOIN ods_hiv_art_clinical hac ON tvs.uuid = hac.vital_sign_uuid AND tvs.ods_datim_id = hac.ods_datim_id
INNER JOIN ods_hiv_enrollment he ON he.person_uuid = hac.person_uuid AND he.ods_datim_id = hac.ods_datim_id
LEFT JOIN ods_base_application_codeset bac ON bac.id = hac.clinical_stage_id AND bac.ods_datim_id = hac.ods_datim_id
LEFT JOIN ods_base_application_codeset preg ON preg.code = hac.pregnancy_status AND preg.ods_datim_id = hac.ods_datim_id
LEFT JOIN ods_base_application_codeset tbs ON tbs.id = CAST(hac.tb_status AS INTEGER) AND tbs.ods_datim_id = hac.ods_datim_id
--LEFT JOIN patient_person pp ON tvs.person_uuid = pp.uuid and tvs.ods_datim_id=pp.ods_datim_id
WHERE hac.archived = 0 AND he.archived = 0
'')AS sm(person_uuid10 character varying,clin_ods_datim_id character varying(255),capture_date date,
currentweight double precision,tbstatus1 character varying,currentclinicalstage character varying,
pregnancystatus character varying,dateoftbscreened1 date,tvs_archived integer)',last_load_end_time);

SELECT TIMEOFDAY() INTO end_time;

ALTER TABLE expanded_radet.sub_tvs_current_clinical_refresh
ADD CONSTRAINT unq_cte_sub_tvs_current_clinical_refresh UNIQUE (person_uuid10,clin_ods_datim_id);

CREATE INDEX unq_dateOfTbScreened1_cte_sub_tvs_current_clinical_refresh 
