--
-- Name: proc_current_status(); Type: PROCEDURE; Schema: expanded_radet; Owner: lamisplus_etl
--

CREATE PROCEDURE expanded_radet.proc_current_status()
    LANGUAGE plpgsql
    AS $$
DECLARE end_time TIMESTAMP;
DECLARE start_time TIMESTAMP;
BEGIN

SELECT TIMEOFDAY() INTO start_time;
DROP TABLE IF EXISTS expanded_radet.sub_pharmacy_current_status;
CREATE TABLE expanded_radet.sub_pharmacy_current_status AS
SELECT * FROM dblink('db_link_ods',
'SELECT hap.person_uuid,hap.ods_datim_id, hap.visit_date, hap.refill_period, 
ROW_NUMBER() OVER (PARTITION BY hap.person_uuid, hap.ods_datim_id ORDER BY hap.visit_date DESC) as rnkkk3 
FROM public.ods_hiv_art_pharmacy hap 
INNER JOIN public.ods_hiv_art_pharmacy_regimens pr ON pr.art_pharmacy_id = hap.id AND pr.ods_datim_id = hap.ods_datim_id
INNER JOIN public.ods_hiv_enrollment h ON h.person_uuid = hap.person_uuid AND h.ods_datim_id = hap.ods_datim_id
AND h.archived = 0 
INNER JOIN public.ods_hiv_regimen r on r.id = pr.regimens_id AND r.ods_datim_id = pr.ods_datim_id
INNER JOIN public.ods_hiv_regimen_type rt on rt.id = r.regimen_type_id AND rt.ods_datim_id = r.ods_datim_id
WHERE 
r.regimen_type_id in (1, 2, 3, 4, 14) 
AND hap.archived = 0 
AND hap.visit_date <= (SELECT date FROM expanded_radet.period WHERE is_active) ---?3
') AS sm(person_uuid character varying, ods_datim_id character varying,visit_date date,
	  refill_period integer,rnkkk3 bigint);

CREATE INDEX maxdate_subpharmacycurrentstatus 
ON expanded_radet.sub_pharmacy_current_status(person_uuid,ods_datim_id,visit_date);

CREATE INDEX row_subpharmacycurrentstatus 
ON expanded_radet.sub_pharmacy_current_status(rnkkk3);

------------------------------------------------------------------------------------------------------

DROP TABLE IF EXISTS expanded_radet.pharmacy_current_status;
CREATE TABLE expanded_radet.pharmacy_current_status AS
SELECT hp.refill_period, hp.visit_date,
(CASE WHEN CAST(hp.visit_date AS DATE) + CAST(hp.refill_period AS INTEGER) + INTERVAL '29 day' > (SELECT date FROM expanded_radet.period WHERE is_active) ---?3 next_appointment + refill_period + 29 days
THEN 'Active' ELSE 'IIT' END) status, 
(CASE WHEN CAST(hp.visit_date AS DATE) + CAST(hp.refill_period AS INTEGER) + INTERVAL '29 day' > (SELECT date FROM expanded_radet.period WHERE is_active) ---?3 
THEN CAST(hp.visit_date AS DATE) ELSE  
  CAST(hp.visit_date AS DATE) + CAST(hp.refill_period AS INTEGER) + INTERVAL '29 day'
END
) AS pharmacy_status_visit_date, 
hp.person_uuid, hp.ods_datim_id 
FROM expanded_radet.sub_pharmacy_current_status hp 
WHERE rnkkk3 = 1 AND hp.refill_period is not null;

--------------------------------------------------------------------------------------------------------

DROP TABLE IF EXISTS expanded_radet.sub_stat_current_status;
CREATE TABLE expanded_radet.sub_stat_current_status AS
SELECT * FROM dblink('db_link_ods',
'SELECT person_id,ods_datim_id,status_date,cause_of_death,va_cause_of_death,hiv_status, 
ROW_NUMBER() OVER (PARTITION BY person_id, ods_datim_id ORDER BY status_date DESC) row_substatcurrentstatus
FROM ods_hiv_status_tracker 
WHERE archived = 0 
AND status_date <= (SELECT date FROM expanded_radet.period WHERE is_active) ----?3
') AS sm(person_id character varying, ods_datim_id character varying, status_date date,
	  cause_of_death character varying, va_cause_of_death character varying, 
	  hiv_status character varying, row_substatcurrentstatus bigint);

CREATE INDEX rownum_substatcurrentstatus
ON expanded_radet.sub_stat_current_status(row_substatcurrentstatus);

----------------------------------------------------------------------------------------------------

DROP TABLE IF EXISTS expanded_radet.sub2_stat_current_status;
CREATE TABLE expanded_radet.sub2_stat_current_status AS
SELECT * FROM expanded_radet.sub_stat_current_status
WHERE row_substatcurrentstatus=1;

CREATE INDEX personidodsdatimid_sub2statcurrentstatus
ON expanded_radet.sub2_stat_current_status(person_id,ods_datim_id);

DROP TABLE if exists expanded_radet.cte_current_status_new;
CREATE TABLE expanded_radet.cte_current_status_new AS 
SELECT DISTINCT ON (pharmacy.person_uuid, pharmacy.ods_datim_id) pharmacy.person_uuid AS cuPersonUuid,
	pharmacy.visit_date AS last_visit_date, pharmacy.pharmacy_status_visit_date, pharmacy.refill_period,
    pharmacy.ods_datim_id as cus_ods_datim_id, 
    ( CASE WHEN stat.hiv_status ILIKE '%DEATH%' OR stat.hiv_status ILIKE '%Died%' THEN 'Died' 
	  WHEN(stat.status_date > pharmacy.visit_date 
	  AND (stat.hiv_status ILIKE '%stop%' OR stat.hiv_status ILIKE '%out%' OR stat.hiv_status ILIKE '%Invalid %')
		) THEN stat.hiv_status ELSE pharmacy.status END
    ) AS status, 
	
    (CASE WHEN stat.hiv_status ILIKE '%DEATH%' OR stat.hiv_status ILIKE '%Died%' THEN CAST(stat.status_date AS DATE) 
	  WHEN(stat.status_date > pharmacy.visit_date 
        AND (stat.hiv_status ILIKE '%stop%' OR stat.hiv_status ILIKE '%out%' 
          OR stat.hiv_status ILIKE '%Invalid %')
      ) THEN CAST(stat.status_date AS DATE) ELSE pharmacy.visit_date END
    ) AS status_date, 
    stat.cause_of_death, 
    stat.va_cause_of_death 
FROM expanded_radet.pharmacy_current_status pharmacy
LEFT JOIN expanded_radet.sub2_stat_current_status stat ON stat.person_id = pharmacy.person_uuid 
AND stat.ods_datim_id = pharmacy.ods_datim_id;

drop table if exists expanded_radet.cte_current_status;
alter table expanded_radet.cte_current_status_new rename to cte_current_status;

DROP TABLE if exists expanded_radet.sub_pharmacy_current_status;
--DROP TABLE IF EXISTS expanded_radet.pharmacy_current_status;
DROP TABLE IF EXISTS expanded_radet.sub_stat_current_status;
DROP TABLE IF EXISTS expanded_radet.sub2_stat_current_status;
DROP TABLE IF EXISTS expanded_radet.stat_current_status;

SELECT TIMEOFDAY() INTO end_time;
INSERT INTO expanded_radet.expanded_radet_monitoring (table_name, start_time,end_time) 
VALUES ('cte_current_status', start_time,end_time);

END
$$;


ALTER PROCEDURE expanded_radet.proc_current_status() OWNER TO lamisplus_etl;

--
-- Name: proc_current_tb_result(); Type: PROCEDURE; Schema: expanded_radet; Owner: lamisplus_etl
--

CREATE PROCEDURE expanded_radet.proc_current_tb_result()
    LANGUAGE plpgsql
    AS $$DECLARE end_time TIMESTAMP;
DECLARE start_time TIMESTAMP;
BEGIN

SELECT TIMEOFDAY() INTO start_time;

DROP TABLE if exists expanded_radet.cte_current_tb_result_new;

CREATE TABLE expanded_radet.cte_current_tb_result_new AS
SELECT * FROM dblink('db_link_ods',
'WITH tb_test as (
	SELECT DISTINCT ON (personTbResult, ods_datim_id)personTbResult, ods_datim_id as curr_ods_datim_id, 
	dateofTbDiagnosticResultReceived,
   coalesce(
           MAX(CASE WHEN lab_test_id = 65 THEN tbDiagnosticResult END) ,
           MAX(CASE WHEN lab_test_id = 51 THEN tbDiagnosticResult END) ,
           MAX(CASE WHEN lab_test_id = 66 THEN tbDiagnosticResult END),
           MAX(CASE WHEN lab_test_id = 64 THEN tbDiagnosticResult END),
           MAX(CASE WHEN lab_test_id = 67 THEN tbDiagnosticResult END),
           MAX(CASE WHEN lab_test_id = 68 THEN tbDiagnosticResult END)
       ) as tbDiagnosticResult ,
   coalesce(
           MAX(CASE WHEN lab_test_id = 65 THEN ''Gene Xpert'' END) ,
           MAX(CASE WHEN lab_test_id = 51 THEN ''TB-LAM'' END) ,
           MAX(CASE WHEN lab_test_id = 66 THEN ''Chest X-ray'' END),
           MAX(CASE WHEN lab_test_id = 64 THEN ''AFB microscopy'' END),
           MAX(CASE WHEN lab_test_id = 67 THEN ''Gene Xpert'' END) ,
           MAX(CASE WHEN lab_test_id = 58 THEN ''TB-LAM'' END)
       ) as tbDiagnosticTestType

        FROM (
     SELECT  DISTINCT ON(sm.patient_uuid, sm.ods_datim_id)sm.patient_uuid as personTbResult,
			sm.ods_datim_id,
			sm.result_reported as tbDiagnosticResult,
 CAST(sm.date_result_reported AS DATE) as dateofTbDiagnosticResultReceived,
 lt.lab_test_id
     FROM ods_laboratory_result  sm
  INNER JOIN ods_laboratory_test  lt on sm.test_id = lt.id and sm.ods_datim_id = lt.ods_datim_id
     WHERE lt.lab_test_id IN (65,51,66,64) and sm.archived = ''0''
       AND sm.date_result_reported is not null
       --AND sm.facility_id = ?1
       AND sm.date_result_reported <= (select date from expanded_radet.period where is_active) ----?3
 ) as dt
        GROUP BY dt.personTbResult, dt.ods_datim_id, dt.dateofTbDiagnosticResultReceived
				)
   select * from (select *, row_number() over (partition by personTbResult, curr_ods_datim_id
         order by dateofTbDiagnosticResultReceived desc ) as rnk from tb_test) as dt
   where rnk = 1') 
AS sm(persontbresult character varying,curr_ods_datim_id character varying(255),dateoftbdiagnosticresultreceived date,
    tbdiagnosticresult text,tbdiagnostictesttype text,rnk bigint);

drop table if exists expanded_radet.cte_current_tb_result;
alter table expanded_radet.cte_current_tb_result_new rename to cte_current_tb_result;

SELECT TIMEOFDAY() INTO end_time;
INSERT INTO expanded_radet.expanded_radet_monitoring (table_name, start_time,end_time) 
VALUES ('cte_current_tb_result', start_time,end_time);
END
$$;


ALTER PROCEDURE expanded_radet.proc_current_tb_result() OWNER TO lamisplus_etl;

--
-- Name: proc_current_vl_result(); Type: PROCEDURE; Schema: expanded_radet; Owner: lamisplus_etl
--

CREATE PROCEDURE expanded_radet.proc_current_vl_result()
    LANGUAGE plpgsql
    AS $$
DECLARE start_time TIMESTAMP; 
DECLARE end_time TIMESTAMP;
BEGIN

SELECT TIMEOFDAY() INTO start_time;

DROP TABLE if exists expanded_radet.cte_current_vl_result_new;

CREATE TABLE expanded_radet.cte_current_vl_result_new AS	
SELECT sm.patient_uuid as person_uuid130,sm.ods_datim_id as cvl_ods_datim_id,
sm.facility_id as vlFacility,sm.archived AS vlArchived,
CAST(ls.date_sample_collected AS DATE) AS dateOfCurrentViralLoadSample,
lt.display AS viralLoadIndication,sm.result_reported AS currentViralLoad,
CAST(sm.date_result_reported AS date) dateOfCurrentViralLoad
FROM expanded_radet.temp_lab_result sm
INNER JOIN expanded_radet.temp_lab_test lt ON sm.test_id = lt.id AND sm.patient_uuid=lt.patient_uuid
AND sm.ods_datim_id = lt.ods_datim_id
INNER JOIN expanded_radet.temp_lab_sample ls ON ls.test_id = lt.id AND ls.patient_uuid=lt.patient_uuid
AND ls.ods_datim_id = lt.ods_datim_id
WHERE ls.date_sample_collected <= (SELECT date FROM expanded_radet.period WHERE is_active) 
--remove the interval when running for weekly
AND CAST(sm.date_result_reported AS date) <= (SELECT date FROM expanded_radet.period WHERE is_active) + INTERVAL '1 month'
AND sm.rank2=1;

DROP INDEX IF EXISTS expanded_radet.idx_cte_current_vl_result;
CREATE INDEX idx_cte_current_vl_result ON expanded_radet.cte_current_vl_result_new (person_uuid130, cvl_ods_datim_id);	

drop table if exists expanded_radet.cte_current_vl_result;
alter table expanded_radet.cte_current_vl_result_new rename to cte_current_vl_result;

SELECT TIMEOFDAY() INTO end_time; 
INSERT INTO expanded_radet.expanded_radet_monitoring (table_name, start_time,end_time)
VALUES ('cte_current_vl_result', start_time,end_time);
END
$$;


ALTER PROCEDURE expanded_radet.proc_current_vl_result() OWNER TO lamisplus_etl;

