CREATE PROCEDURE expanded_radet.proc_ipt()
    LANGUAGE plpgsql
    AS $$DECLARE end_time TIMESTAMP;
DECLARE start_time TIMESTAMP;
BEGIN

SELECT TIMEOFDAY() INTO start_time;

DROP TABLE if exists expanded_radet.cte_ipt_new;

CREATE TABLE expanded_radet.cte_ipt_new AS 
SELECT DISTINCT ON (c.person_uuid, c.ipt_c_ods_datim_id) c.person_uuid AS personuuid80, c.ipt_c_ods_datim_id 
AS cte_ipt_ods_datim_id, 
coalesce(cs.iptCompletionDSC, c.iptCompletionDate) as iptCompletionDate, 
coalesce(cs.iptCompletionSCS, c.iptCompletionStatus) as iptCompletionStatus, s.dateOfIptStart, s.iptType 
from expanded_radet.sub_cte_ipt_c c
left join expanded_radet.sub_cte_ipt_s s on s.person_uuid = c.person_uuid 
AND s.ipt_s_ods_datim_id=c.ipt_c_ods_datim_id
left join expanded_radet.sub_cte_ipt_c_cs  cs on s.person_uuid = cs.person_uuid 
AND cs.ipt_c_cs_ods_datim_id=s.ipt_s_ods_datim_id;

drop table if exists expanded_radet.cte_ipt;
alter table expanded_radet.cte_ipt_new rename to cte_ipt;

SELECT TIMEOFDAY() INTO end_time;
INSERT INTO expanded_radet.expanded_radet_monitoring (table_name, start_time,end_time) 
VALUES ('cte_ipt', start_time,end_time);
END
$$;


ALTER PROCEDURE expanded_radet.proc_ipt() OWNER TO lamisplus_etl;

--
-- Name: proc_labcd4(); Type: PROCEDURE; Schema: expanded_radet; Owner: lamisplus_etl
--

CREATE PROCEDURE expanded_radet.proc_labcd4()
    LANGUAGE plpgsql
    AS $$DECLARE start_time TIMESTAMP;
DECLARE end_time TIMESTAMP;
BEGIN

SELECT TIMEOFDAY() INTO start_time;

DROP TABLE if exists expanded_radet.cte_labcd4_new;
CREATE TABLE expanded_radet.cte_labcd4_new AS
SELECT * FROM dblink('db_link_ods',
'SELECT * 
  FROM (SELECT sm.patient_uuid AS cd4_person_uuid,sm.ods_datim_id as lab_ods_datim_id,sm.result_reported as cd4Lb, 
        sm.date_result_reported as dateOfCD4Lb,
        ROW_NUMBER () OVER (PARTITION BY sm.patient_uuid, sm.ods_datim_id ORDER BY date_result_reported DESC) as rnk 
      FROM public.ods_laboratory_result sm 
        INNER JOIN public.ods_laboratory_test lt on sm.test_id = lt.id AND sm.ods_datim_id = lt.ods_datim_id
      WHERE lt.lab_test_id IN (1, 50) AND sm.date_result_reported IS NOT NULL 
        AND sm.archived = ''0''
        AND sm.date_result_reported <= (select date from expanded_radet.period where is_active) ---?3
    ) as cd4_result WHERE cd4_result.rnk = 1')
AS sm(cd4_person_uuid character varying,lab_ods_datim_id character varying(255),cd4lb character varying,
    dateofcd4lb timestamp without time zone,rnk bigint);

drop table if exists expanded_radet.cte_labcd4;
alter table expanded_radet.cte_labcd4_new rename to cte_labcd4;

SELECT TIMEOFDAY() INTO end_time;
INSERT INTO expanded_radet.expanded_radet_monitoring (table_name, start_time,end_time) 
VALUES ('cte_labcd4', start_time,end_time);
END
$$;


ALTER PROCEDURE expanded_radet.proc_labcd4() OWNER TO lamisplus_etl;

--
-- Name: proc_loop_through_labresults1(); Type: PROCEDURE; Schema: expanded_radet; Owner: lamisplus_etl
--

CREATE PROCEDURE expanded_radet.proc_loop_through_labresults1()
    LANGUAGE plpgsql
    AS $$
DECLARE
    lab_tests TEXT[];
    lab_test TEXT;
    start_time TIMESTAMP;
    last_load_end_time TIMESTAMP;
    record_count BIGINT;
    end_time TIMESTAMP;
BEGIN
    -- Fetch the last load end time
    SELECT MAX(load_end_time) 
    INTO last_load_end_time
    FROM streaming_remote_monitoring
    WHERE table_name = 'lab_test_results_refresh1';

    -- Fetch record count from the remote database using dblink
    EXECUTE FORMAT(
        'SELECT *
         FROM dblink(''db_link_ods'',
         ''SELECT count(uuid) 
           FROM ods_laboratory_test 
           WHERE ods_load_time >= ''%L''
		   AND lab_test_id = 1 
         '') 
         AS sm(count BIGINT)', last_load_end_time) 
    INTO record_count;

    -- Populate the array with values from the existing table
    SELECT array_agg(distinct lab_test_name)
	INTO lab_tests
	FROM public.lab_test_name
	WHERE lab_test_name IS NOT NULL
	AND id = 1;

    SELECT TIMEOFDAY() INTO start_time;

    -- Loop through each lab test and call the processing function
    FOREACH lab_test IN ARRAY lab_tests
    LOOP
        -- Call the function to process each lab test
        PERFORM expanded_radet.process_lab_test(lab_test, last_load_end_time);
    END LOOP;

    SELECT TIMEOFDAY() INTO end_time;

    DELETE FROM expanded_radet.lab_test_results_refresh
    WHERE archived = 1;

    INSERT INTO public.streaming_remote_monitoring(table_name, start_time, load_end_time, record_count)
    VALUES('lab_test_results_refresh1', start_time, end_time, record_count);
END;
$$;


ALTER PROCEDURE expanded_radet.proc_loop_through_labresults1() OWNER TO lamisplus_etl;

