--

CREATE PROCEDURE expanded_radet.proc_loop_through_labresults15()
    LANGUAGE plpgsql
    AS $$
DECLARE
    lab_tests TEXT[];
    lab_test TEXT;
    start_time TIMESTAMP;
    last_load_end_time TIMESTAMP;
    record_count BIGINT;
    end_time TIMESTAMP;
BEGIN
    -- Fetch the last load end time
    SELECT MAX(load_end_time) 
    INTO last_load_end_time
    FROM streaming_remote_monitoring
    WHERE table_name = 'lab_test_results_refresh15';

    -- Fetch record count from the remote database using dblink
    EXECUTE FORMAT(
        'SELECT *
         FROM dblink(''db_link_ods'',
         ''SELECT count(uuid) 
           FROM ods_laboratory_test 
           WHERE ods_load_time >= ''%L''
		   AND lab_test_id = 5
         '') 
         AS sm(count BIGINT)', last_load_end_time) 
    INTO record_count;

    -- Populate the array with values from the existing table
    SELECT array_agg(distinct lab_test_name)
	INTO lab_tests
	FROM public.lab_test_name
	WHERE lab_test_name IS NOT NULL
	AND id = 5;

    SELECT TIMEOFDAY() INTO start_time;

    -- Loop through each lab test and call the processing function
    FOREACH lab_test IN ARRAY lab_tests
    LOOP
        -- Call the function to process each lab test
        PERFORM expanded_radet.process_lab_test(lab_test, last_load_end_time);
    END LOOP;

    SELECT TIMEOFDAY() INTO end_time;

    DELETE FROM expanded_radet.lab_test_results_refresh
    WHERE archived = 1;

    INSERT INTO public.streaming_remote_monitoring(table_name, start_time, load_end_time, record_count)
    VALUES('lab_test_results_refresh15', start_time, end_time, record_count);
END;
$$;


ALTER PROCEDURE expanded_radet.proc_loop_through_labresults15() OWNER TO lamisplus_etl;

