--
-- Name: proc_loop_through_lists(); Type: PROCEDURE; Schema: expanded_radet; Owner: lamisplus_etl
--

CREATE PROCEDURE expanded_radet.proc_loop_through_lists()
    LANGUAGE plpgsql
    AS $$
DECLARE
    inputs text[];
    input text;
    partition_name text;
BEGIN
    -- Populate the array with values from the existing table
    SELECT array_agg(periodid) 
    INTO inputs
    FROM public.period;

    -- Loop through each input value and execute the dynamic query
    FOREACH input IN ARRAY inputs
    LOOP
        partition_name := CONCAT('aggregate_flatfile_', input);
        
		EXECUTE format('
            DROP TABLE IF EXISTS public.%I 
           ', partition_name);
			
        -- Loop through and create partitions
        EXECUTE format('
            CREATE TABLE IF NOT EXISTS public.%I 
            PARTITION OF public.aggregate_flatfile_backup
            FOR VALUES IN (%L)', partition_name, input);
    END LOOP;
END;
$$;


ALTER PROCEDURE expanded_radet.proc_loop_through_lists() OWNER TO lamisplus_etl;

--
-- Name: proc_naive_vl_data(); Type: PROCEDURE; Schema: expanded_radet; Owner: lamisplus_etl
--

CREATE PROCEDURE expanded_radet.proc_naive_vl_data()
    LANGUAGE plpgsql
    AS $$
DECLARE end_time TIMESTAMP;
DECLARE start_time TIMESTAMP;
BEGIN
SELECT TIMEOFDAY() INTO start_time;

DROP TABLE if exists expanded_radet.cte_naive_vl_data_new;
  
CREATE TABLE expanded_radet.cte_naive_vl_data_new AS
SELECT pp.uuid AS nvl_person_uuid,pp.ods_datim_id as nvl_ods_datim_id,
EXTRACT(YEAR FROM AGE(NOW(), CAST(pp.date_of_birth AS DATE))) as age, 
ph.visit_date, ph.regimen
-- (SELECT * FROM dblink('db_link_ods',
-- 	'SELECT DISTINCT ON (uuid,ods_datim_id) uuid, ods_datim_id,date_of_birth
-- 	FROM ods_patient_person limit 1')
-- 	AS sm(uuid character varying,ods_datim_id character varying(255),
-- 		date_of_birth date))
FROM (select personuuid as uuid,bio_ods_datim_id as ods_datim_id,
	  dateofbirth as date_of_birth
from expanded_radet.patient_bio_data) pp
INNER JOIN expanded_radet.cte_sub_naive_vl_data ph 
ON ph.person_uuid = pp.uuid AND ph.ods_datim_id_hap = pp.ods_datim_id
WHERE NOT EXISTS (SELECT 1 
FROM expanded_radet.cte_sub2_naive_vl_data sub2 
WHERE sub2.patient_uuid = pp.uuid AND sub2.ods_datim_id = pp.ods_datim_id);

drop table if exists expanded_radet.cte_naive_vl_data;

alter table expanded_radet.cte_naive_vl_data_new rename to cte_naive_vl_data;

SELECT TIMEOFDAY() INTO end_time;
INSERT INTO expanded_radet.expanded_radet_monitoring (table_name, start_time,end_time) 
VALUES ('cte_naive_vl_data', start_time,end_time);
END
$$;


ALTER PROCEDURE expanded_radet.proc_naive_vl_data() OWNER TO lamisplus_etl;

