CREATE PROCEDURE expanded_radet.proc_ovc()
    LANGUAGE plpgsql
    AS $$DECLARE start_time TIMESTAMP;
DECLARE end_time TIMESTAMP;
BEGIN
SELECT TIMEOFDAY() INTO start_time;

DROP TABLE if exists expanded_radet.cte_ovc_new;

CREATE TABLE expanded_radet.cte_ovc_new AS
SELECT * FROM dblink('db_link_ods',
'SELECT DISTINCT ON (person_uuid, ods_datim_id) person_uuid AS personUuid100, 
ods_datim_id as ovc_ods_datim_id,ovc_number AS ovcNumber, house_hold_number AS householdNumber 
FROM ods_hiv_enrollment')
AS sm(personuuid100 character varying, ovc_ods_datim_id character varying(255),
    ovcnumber character varying,householdnumber character varying);

drop table if exists expanded_radet.cte_ovc;
alter table expanded_radet.cte_ovc_new rename to cte_ovc;

CREATE INDEX personuuid_pvcodsdatim_cteovc 
ON expanded_radet.cte_ovc(personuuid100,ovc_ods_datim_id);

SELECT TIMEOFDAY() INTO end_time;
INSERT INTO expanded_radet.expanded_radet_monitoring (table_name, start_time,end_time) 
VALUES ('cte_ovc', start_time,end_time);
END
$$;


ALTER PROCEDURE expanded_radet.proc_ovc() OWNER TO lamisplus_etl;

--
-- Name: proc_patient_lga(); Type: PROCEDURE; Schema: expanded_radet; Owner: lamisplus_etl
--

CREATE PROCEDURE expanded_radet.proc_patient_lga()
    LANGUAGE plpgsql
    AS $_$DECLARE end_time TIMESTAMP;
DECLARE start_time TIMESTAMP;
BEGIN

SELECT TIMEOFDAY() INTO start_time;

DROP TABLE IF EXISTS expanded_radet.cte_patient_lga_new;
CREATE TABLE expanded_radet.cte_patient_lga_new AS
SELECT * FROM dblink('db_link_ods',
'select DISTINCT ON (ods_datim_id, personUuid) personUuid as personUuid11,  
case when (addr ~ ''^[0-9\\\\.]$'') =TRUE  
then (select distinct name from ods_base_organisation_unit 
	  where id = cast(addr as int) limit 1) ELSE
(select distinct name from ods_base_organisation_unit 
 where id = cast(facilityLga as int) limit 1) end as lgaOfResidence  
from (
select distinct on (pp.uuid, ods_datim_id) pp.uuid AS personUuid, pp.ods_datim_id,  
	facility_lga.parent_organisation_unit_id AS facilityLga, 
	(jsonb_array_elements(pp.address->''address'')->>''district'') as addr 
	from ods_patient_person pp
LEFT JOIN ods_base_organisation_unit facility_lga 
	ON facility_lga.id = CAST (pp.organization->''id'' AS INTEGER)  and
facility_lga.ods_datim_id=pp.ods_datim_id
) dt')
AS sm(personuuid11 character varying,lgaofresidence character varying);

drop table if exists expanded_radet.cte_patient_lga;
alter table expanded_radet.cte_patient_lga_new rename to cte_patient_lga;
	
SELECT TIMEOFDAY() INTO end_time;
INSERT INTO expanded_radet.expanded_radet_monitoring (table_name, start_time,end_time) 
VALUES ('cte_patient_lga', start_time,end_time);
END
$_$;


ALTER PROCEDURE expanded_radet.proc_patient_lga() OWNER TO lamisplus_etl;

--
-- Name: proc_patient_status(); Type: PROCEDURE; Schema: expanded_radet; Owner: lamisplus_etl
--

CREATE PROCEDURE expanded_radet.proc_patient_status()
    LANGUAGE plpgsql
    AS $$
DECLARE
    start_time TIMESTAMP;
    end_time TIMESTAMP;
    partition_name CHARACTER VARYING;
	constraint_check TEXT;
    period_date DATE;
    period_text TEXT;
    period_start DATE;
    period_end DATE;
BEGIN
-- Capture start time
SELECT TIMEOFDAY() INTO start_time;

-- Retrieve period dates and partition name
SELECT start_date INTO period_start
FROM expanded_radet.period
WHERE is_active;

SELECT date INTO period_end
FROM expanded_radet.period
WHERE is_active;

SELECT CONCAT('patient_status','_',periodid)
--REPLACE(table_name, 'expanded_radet_weekly', 'patient_status') table_name 
INTO partition_name
FROM expanded_radet.period
WHERE is_active;

SELECT CONCAT('patient_status','_',periodid,'_check')
--CONCAT(REPLACE(table_name, 'final_radet_quartely', 'patient_status'),'_check') 
INTO constraint_check
FROM expanded_radet.period
WHERE is_active;

SELECT periodid INTO period_text
FROM expanded_radet.period
WHERE is_active;

SELECT date INTO period_date 
FROM expanded_radet.period
WHERE is_active;

-- SELECT date INTO period_end
-- FROM expanded_radet.period
-- WHERE is_active;

-- Create temp table with dynamic SQL
DROP TABLE IF EXISTS expanded_radet.temp_pharmacy_status;
CREATE TABLE IF NOT EXISTS expanded_radet.temp_pharmacy_status AS 
SELECT  
	hp.refill_period,
	(CASE 
		WHEN CAST(hp.visit_date AS DATE) + CAST(hp.refill_period AS INTEGER) + INTERVAL '29 day' < '2024-09-30'
		THEN 'IIT' ELSE 'Active' END) AS status, 
	(CASE WHEN CAST(hp.visit_date AS DATE) + CAST(hp.refill_period AS INTEGER) 
			   + INTERVAL '29 day' < '2024-09-30'
		THEN CAST(hp.visit_date AS DATE) + CAST(hp.refill_period AS INTEGER) + INTERVAL '29 day'
		ELSE CAST(hp.visit_date AS DATE) 
	END) AS pharmacy_status_date, 
			   hp.visit_date,
	hp.person_uuid40, hp.pharma_ods_datim_id
FROM expanded_radet.pharmacy_details_regimen hp 
INNER JOIN (
	SELECT person_uuid40 AS person_uuid, pharma_ods_datim_id AS ods_datim_id, 
	MAX(visit_date) AS MAXDATE
	FROM expanded_radet.pharmacy_details_regimen
	GROUP BY person_uuid40, pharma_ods_datim_id
) MAX ON MAX.MAXDATE = hp.visit_date 
AND MAX.person_uuid = hp.person_uuid40 
AND MAX.ods_datim_id = hp.pharma_ods_datim_id
AND hp.refill_period IS NOT NULL 
AND hp.visit_date <= '2024-09-30'
AND hp.regimen_type_id IN (1, 2, 3, 4, 14);

CREATE INDEX idx_personuuid40datim_temp_pharmacy_status
ON expanded_radet.temp_pharmacy_status(person_uuid40,pharma_ods_datim_id);

-- Create temp table with dynamic SQL
DROP TABLE IF EXISTS expanded_radet.sub_temp_hiv_status_tracker;
CREATE TABLE IF NOT EXISTS expanded_radet.sub_temp_hiv_status_tracker AS 
SELECT DISTINCT ON (person_id, ods_datim_id) person_id, ods_datim_id, status_date, 
	   cause_of_death, va_cause_of_death, hiv_status, 
	   ROW_NUMBER() OVER (PARTITION BY person_id, ods_datim_id ORDER BY status_date DESC) 
FROM expanded_radet.hiv_status_tracker_refresh
WHERE status_date <= '2024-09-30';

CREATE INDEX idx_personiddatim_sub_temp_hiv_status_tracker
ON expanded_radet.sub_temp_hiv_status_tracker(row_number);

DROP TABLE IF EXISTS expanded_radet.temp_hiv_status_tracker;
CREATE TABLE IF NOT EXISTS expanded_radet.temp_hiv_status_tracker AS 
SELECT * FROM expanded_radet.sub_temp_hiv_status_tracker
WHERE row_number=1;

CREATE INDEX idx_personiddatim_temp_hiv_status_tracker
ON expanded_radet.temp_hiv_status_tracker(person_id,ods_datim_id);

EXECUTE format('DROP TABLE IF EXISTS expanded_radet.%I',partition_name);

-- Create new partition table
EXECUTE format('
CREATE TABLE IF NOT EXISTS expanded_radet.%I PARTITION OF expanded_radet.patient_status
FOR VALUES IN (%L)',partition_name,period_text);

EXECUTE format('
    ALTER TABLE expanded_radet.%I
    ADD CONSTRAINT %I CHECK (period=%L)', partition_name, constraint_check, period_text);

-- Insert data into the new partition table
INSERT INTO expanded_radet.patient_status
SELECT DISTINCT ON (pharmacy.person_uuid40, pharmacy.pharma_ods_datim_id) pharmacy.person_uuid40 AS cuPersonUuid,
	pharmacy.visit_date AS last_visit_date, pharmacy.refill_period,
    pharmacy.pharma_ods_datim_id as cus_ods_datim_id, 
    ( CASE WHEN stat.hiv_status ILIKE '%DEATH%' OR stat.hiv_status ILIKE '%Died%' THEN 'Died' 
	  WHEN(stat.status_date > pharmacy.visit_date 
	  AND (stat.hiv_status ILIKE '%stop%' OR stat.hiv_status ILIKE '%out%' OR stat.hiv_status ILIKE '%Invalid%')
		) THEN stat.hiv_status ELSE pharmacy.status END
    ) AS status, 
    (
      CASE WHEN stat.hiv_status ILIKE '%DEATH%' 
      OR stat.hiv_status ILIKE '%Died%' THEN CAST(stat.status_date AS DATE) 
	  WHEN(
        stat.status_date > pharmacy.visit_date 
        AND (
          stat.hiv_status ILIKE '%stop%' 
          OR stat.hiv_status ILIKE '%out%' 
          OR stat.hiv_status ILIKE '%Invalid %'
        )
      ) THEN CAST(stat.status_date AS DATE) ELSE pharmacy.pharmacy_status_date END
    ) AS status_date, 
    stat.cause_of_death, 
    stat.va_cause_of_death,
	'2024Q4' AS period,
	'2024-06-01' AS period_start_date,
	'2024-09-30' period_end_date,
	pharmacy.pharmacy_status_date
	FROM expanded_radet.temp_pharmacy_status pharmacy
	INNER JOIN expanded_radet.temp_hiv_status_tracker stat ON stat.ods_datim_id=pharmacy.pharma_ods_datim_id
	AND stat.person_id=pharmacy.person_uuid40
	WHERE stat.status_date >= '1980-01-01' AND stat.status_date <= '2024-09-30'
	AND pharmacy.visit_date <= '2024-09-30';

CREATE INDEX IF NOT EXISTS idx_periodstartperiodend_patient_status
ON expanded_radet.patient_status(period_start_date,period_end_date);

-- Capture end time
SELECT TIMEOFDAY() INTO end_time;

-- Log the monitoring information
INSERT INTO expanded_radet.expanded_radet_monitoring (table_name, start_time, end_time)
VALUES (partition_name, start_time, end_time);
END
$$;


