CREATE PROCEDURE expanded_radet.proc_previous()
    LANGUAGE plpgsql
    AS $$
DECLARE end_time TIMESTAMP;
DECLARE start_time TIMESTAMP;
BEGIN

SELECT TIMEOFDAY() INTO start_time;
DROP TABLE IF EXISTS expanded_radet.sub_pharmacy_previous_status;
CREATE TABLE expanded_radet.sub_pharmacy_previous_status AS
SELECT * FROM dblink('db_link_ods',
'SELECT hap.person_uuid,hap.ods_datim_id, hap.visit_date, hap.refill_period, 
ROW_NUMBER() OVER (PARTITION BY hap.person_uuid, hap.ods_datim_id ORDER BY hap.visit_date DESC) as rnkkk3 
FROM public.ods_hiv_art_pharmacy hap 
INNER JOIN public.ods_hiv_art_pharmacy_regimens pr ON pr.art_pharmacy_id = hap.id AND pr.ods_datim_id = hap.ods_datim_id
INNER JOIN public.ods_hiv_enrollment h ON h.person_uuid = hap.person_uuid AND h.ods_datim_id = hap.ods_datim_id
AND h.archived = 0 
INNER JOIN public.ods_hiv_regimen r on r.id = pr.regimens_id AND r.ods_datim_id = pr.ods_datim_id
INNER JOIN public.ods_hiv_regimen_type rt on rt.id = r.regimen_type_id AND rt.ods_datim_id = r.ods_datim_id
WHERE 
r.regimen_type_id in (1, 2, 3, 4, 14) 
AND hap.archived = 0 
AND hap.visit_date <= (SELECT cast(to_char(date_trunc(''quarter'', date (cast((select date from expanded_radet.period where is_active) as varchar)))::date - 1,''yyyy-MM-DD'') as date) as date) ----?4
')AS sm(person_uuid character varying, ods_datim_id character varying,visit_date date,
	  refill_period integer,rnkkk3 bigint);

CREATE INDEX maxdate_subpharmacypreviousstatus 
ON expanded_radet.sub_pharmacy_previous_status(person_uuid,ods_datim_id,visit_date);

CREATE INDEX row_subpharmacypreviousstatus 
ON expanded_radet.sub_pharmacy_previous_status(rnkkk3);

------------------------------------------------------------------------------------------------------

DROP TABLE IF EXISTS expanded_radet.pharmacy_previous_status;
CREATE TABLE expanded_radet.pharmacy_previous_status AS
SELECT hp.refill_period, hp.visit_date,
(CASE WHEN CAST(hp.visit_date AS DATE) + CAST(hp.refill_period AS INTEGER) + INTERVAL '29 day' > (SELECT cast(to_char(date_trunc('quarter', date (cast((select date from expanded_radet.period where is_active) as varchar)))::date - 1,'yyyy-MM-DD') as date) as date) ----?4 next_appointment + refill_period + 29 days
THEN 'Active' ELSE 'IIT' END) status, 
(CASE WHEN CAST(hp.visit_date AS DATE) + CAST(hp.refill_period AS INTEGER) + INTERVAL '29 day' > (SELECT cast(to_char(date_trunc('quarter', date (cast((select date from expanded_radet.period where is_active) as varchar)))::date - 1,'yyyy-MM-DD') as date) as date) ----?4 
THEN CAST(hp.visit_date AS DATE) ELSE  
  CAST(hp.visit_date AS DATE) + CAST(hp.refill_period AS INTEGER) + INTERVAL '29 day'
END
) AS pharmacy_status_visit_date, 
hp.person_uuid, hp.ods_datim_id 
FROM expanded_radet.sub_pharmacy_previous_status hp 
WHERE rnkkk3 = 1 AND hp.refill_period is not null;

--------------------------------------------------------------------------------------------------------

DROP TABLE IF EXISTS expanded_radet.sub_stat_previous_status;
CREATE TABLE expanded_radet.sub_stat_previous_status AS
SELECT * FROM dblink('db_link_ods',
'SELECT person_id,ods_datim_id,status_date,cause_of_death,va_cause_of_death,hiv_status, 
ROW_NUMBER() OVER (PARTITION BY person_id, ods_datim_id ORDER BY status_date DESC) row_substatpreviousstatus
FROM ods_hiv_status_tracker 
WHERE archived = 0 
AND status_date <= (SELECT cast(to_char(date_trunc(''quarter'', date (cast((select date from expanded_radet.period where is_active) as varchar)))::date - 1,''yyyy-MM-DD'') as date) as date) ----?4
')AS sm(person_id character varying, ods_datim_id character varying, status_date date,
	  cause_of_death character varying, va_cause_of_death character varying, 
	  hiv_status character varying, row_substatpreviousstatus bigint);

CREATE INDEX rownum_substatpreviousstatus
ON expanded_radet.sub_stat_previous_status(row_substatpreviousstatus);

----------------------------------------------------------------------------------------------------

DROP TABLE IF EXISTS expanded_radet.sub2_stat_previous_status;
CREATE TABLE expanded_radet.sub2_stat_previous_status AS
SELECT * FROM expanded_radet.sub_stat_previous_status
WHERE row_substatpreviousstatus=1;

CREATE INDEX personidodsdatimid_sub2statpreviousstatus
ON expanded_radet.sub2_stat_previous_status(person_id,ods_datim_id);

