--SELECT hst.hiv_status,hst.person_id,hst.ods_datim_id,hst.cause_of_death,hst.va_cause_of_death,hst.status_date 
--FROM expanded_radet.sub2_stat_previous_status hst 
--INNER JOIN ods_hiv_enrollment he ON he.person_uuid = hst.person_id AND he.ods_datim_id = hst.ods_datim_id
--WHERE hst.status_date <= (SELECT cast(to_char(date_trunc('quarter', date (cast((select date from expanded_radet.period where is_active) as varchar)))::date - 1,'yyyy-MM-DD') as date) as date) ----?4
--;

--CREATE INDEX personidodsdatimid_statpreviousstatus
--ON expanded_radet.stat_previous_status(person_id,ods_datim_id);

DROP TABLE if exists expanded_radet.cte_previous_new;
CREATE TABLE expanded_radet.cte_previous_new AS 
SELECT DISTINCT ON (pharmacy.person_uuid, pharmacy.ods_datim_id) pharmacy.person_uuid AS prePersonUuid,
	pharmacy.visit_date AS last_visit_date, pharmacy.pharmacy_status_visit_date, pharmacy.refill_period,
    pharmacy.ods_datim_id as pre_ods_datim_id, 
    ( CASE WHEN stat.hiv_status ILIKE '%DEATH%' OR stat.hiv_status ILIKE '%Died%' THEN 'Died' 
	  WHEN(stat.status_date > pharmacy.visit_date 
	  AND (stat.hiv_status ILIKE '%stop%' OR stat.hiv_status ILIKE '%out%' OR stat.hiv_status ILIKE '%Invalid %')
		) THEN stat.hiv_status ELSE pharmacy.status END
    ) AS status, 
	
    (CASE WHEN stat.hiv_status ILIKE '%DEATH%' OR stat.hiv_status ILIKE '%Died%' THEN CAST(stat.status_date AS DATE) 
	  WHEN(stat.status_date > pharmacy.visit_date 
        AND (stat.hiv_status ILIKE '%stop%' OR stat.hiv_status ILIKE '%out%' 
          OR stat.hiv_status ILIKE '%Invalid %')
      ) THEN CAST(stat.status_date AS DATE) ELSE pharmacy.visit_date END
    ) AS status_date, 
    stat.cause_of_death, 
    stat.va_cause_of_death 
FROM expanded_radet.pharmacy_previous_status pharmacy
LEFT JOIN expanded_radet.sub2_stat_previous_status stat ON stat.person_id = pharmacy.person_uuid 
AND stat.ods_datim_id = pharmacy.ods_datim_id;

drop table if exists expanded_radet.cte_previous;
