--
-- Name: proc_sub1_eac(); Type: PROCEDURE; Schema: expanded_radet; Owner: lamisplus_etl
--

CREATE PROCEDURE expanded_radet.proc_sub1_eac()
    LANGUAGE plpgsql
    AS $$
DECLARE end_time TIMESTAMP;
DECLARE start_time TIMESTAMP;
BEGIN

SELECT TIMEOFDAY() INTO start_time;

DROP TABLE if exists expanded_radet.sub1_eac_new;

CREATE TABLE expanded_radet.sub1_eac_new AS 
SELECT * FROM dblink('db_link_ods',
'SELECT eac_id, person_uuid, ods_datim_id,
MAX(CASE status WHEN ''FIRST EAC'' THEN eac_session_date ELSE NULL END) AS firsteac,
MAX(CASE status WHEN ''SECOND EAC'' THEN eac_session_date ELSE NULL END) AS secondeac,
MAX(CASE status WHEN ''THIRD EAC'' THEN eac_session_date ELSE NULL END)  AS thirdeac,
MAX(CASE WHEN status not in (''THIRD EAC'', ''SECOND EAC'', ''FIRST EAC'') THEN eac_session_date ELSE NULL END)  AS extendedeac,
COUNT(eac_session_date) AS numberofeacsessions
from ods_hiv_eac_session
WHERE archived=0 AND eac_session_date between ''1980-01-01'' and (select date from expanded_radet.period where is_active)
GROUP BY 1, 2, 3')
SM (eac_id character varying,person_uuid  character varying, ods_datim_id character varying(255),firsteac date,
    secondeac date, thirdeac date, extendedeac date, numberofeacsessions bigint);

drop table if exists expanded_radet.sub1_eac;
alter table expanded_radet.sub1_eac_new rename to sub1_eac;

CREATE INDEX personuuidodsdatimid_sub1_eac ON expanded_radet.sub1_eac(person_uuid,ods_datim_id);

SELECT TIMEOFDAY() INTO end_time;
INSERT INTO expanded_radet.expanded_radet_monitoring (table_name, start_time,end_time) 
VALUES ('sub1_eac', start_time,end_time);
END
$$;


