--
-- Name: proc_sub2_eac(); Type: PROCEDURE; Schema: expanded_radet; Owner: lamisplus_etl
--

CREATE PROCEDURE expanded_radet.proc_sub2_eac()
    LANGUAGE plpgsql
    AS $$
DECLARE end_time TIMESTAMP;
DECLARE start_time TIMESTAMP;
BEGIN

SELECT TIMEOFDAY() INTO start_time;

DROP TABLE if exists expanded_radet.sub2_eac_new;

CREATE TABLE expanded_radet.sub2_eac_new AS 
SELECT * FROM dblink('db_link_ods',
'select lt.patient_uuid, lt.ods_datim_id, cast(ls.date_sample_collected as date), lr.result_reported, 
cast(lr.date_result_reported as date), 
ROW_NUMBER() OVER (PARTITION BY lt.patient_uuid,lt.ods_datim_id ORDER BY ls.date_sample_collected DESC) AS row 
from ods_laboratory_test lt 
left join ods_laboratory_sample ls on ls.test_id = lt.id and ls.ods_datim_id=lt.ods_datim_id
left join ods_laboratory_result lr on lr.test_id = lt.id and lr.ods_datim_id=lt.ods_datim_id
where lt.viral_load_indication = ''302'' and lt.archived = ''0'' and ls.archived = ''0''
AND lt.viral_load_indication IS NOT NULL AND lt.viral_load_indication!=0
and ls.date_sample_collected between ''1980-01-01''
and (select date from expanded_radet.period where is_active)')
SM (patient_uuid character varying,ods_datim_id  character varying, date_sample_collected date, result_reported character varying,
    date_result_reported date, row integer);

drop table if exists expanded_radet.sub2_eac;
alter table expanded_radet.sub2_eac_new rename to sub2_eac;

CREATE INDEX patientuuidodsdatimid_sub2_eac 
ON expanded_radet.sub2_eac(patient_uuid,ods_datim_id);

SELECT TIMEOFDAY() INTO end_time;
INSERT INTO expanded_radet.expanded_radet_monitoring (table_name, start_time,end_time) 
VALUES ('sub2_eac', start_time,end_time);
END
$$;


ALTER PROCEDURE expanded_radet.proc_sub2_eac() OWNER TO lamisplus_etl;

