AND current_clinical_date.person_uuid = tvs.person_uuid10 AND current_clinical_date.ods_datim_id = tvs.clin_ods_datim_id 
WHERE tvs.dateoftbscreened1 <= (SELECT date FROM expanded_radet.period WHERE is_active);

drop table if exists expanded_radet.cte_test_current_clinical;
alter table expanded_radet.cte_test_current_clinical_new rename to cte_test_current_clinical;

