-- Name: proc_update_hiv_status_tracker(); Type: PROCEDURE; Schema: expanded_radet; Owner: lamisplus_etl
--

CREATE PROCEDURE expanded_radet.proc_update_hiv_status_tracker()
    LANGUAGE plpgsql
    AS $$
DECLARE start_time TIMESTAMP;
DECLARE end_time TIMESTAMP;
BEGIN

SELECT TIMEOFDAY() INTO start_time;

PERFORM dblink('db_link_ods',
    format('UPDATE ods_hiv_status_tracker 
         SET hiv_status = biometric_status 
         WHERE biometric_status IS NOT NULL 
           AND biometric_status != ''''
           AND (biometric_status ILIKE ''%%invalid%%'' 
                OR biometric_status ILIKE ''%%duplicate%%'')
           AND (hiv_status NOT ILIKE ''%%art%%'' 
                AND hiv_status NOT ILIKE ''%%died%%'' 
                AND hiv_status NOT ILIKE ''%%death%%'' 
                AND hiv_status NOT ILIKE ''%%stop%%'' 
                AND hiv_status NOT ILIKE ''%%transfer%%'')'));



SELECT TIMEOFDAY() INTO end_time;

INSERT INTO expanded_radet.expanded_radet_monitoring (table_name, start_time,end_time) 
VALUES ('ods_hiv_status_tracker', start_time,end_time);
END
$$;


