--
-- Name: proc_upsert_art_commencement_vitals_refresh(); Type: PROCEDURE; Schema: expanded_radet; Owner: lamisplus_etl
--

CREATE PROCEDURE expanded_radet.proc_upsert_art_commencement_vitals_refresh()
    LANGUAGE plpgsql
    AS $$
DECLARE start_time TIMESTAMP;
DECLARE last_load_end_time TIMESTAMP;
DECLARE end_time TIMESTAMP;
DECLARE record_count bigint;

BEGIN

-- Fetch the last load end time
SELECT MAX(load_end_time) 
INTO last_load_end_time
FROM streaming_remote_monitoring
WHERE table_name = 'art_commencement_vitals_refresh';

-- Fetch record count from the remote database using dblink
EXECUTE FORMAT(
	'SELECT *
	 FROM dblink(''db_link_ods'',
	 ''
	 SELECT count(uuid) 
	 FROM ods_triage_vital_sign 
	 WHERE ods_load_time >= ''%L''			   
	'') 
	 AS sm(count bigint)',last_load_end_time) 
INTO record_count;

-- Use a temporary table to capture the rows affected by the upsert
--CREATE TEMP TABLE temp_upsert_laboatory_details_refresh (
--		uuid character varying,
  --      person_uuid character varying,
    --    ods_datim_id character varying
   -- );
	

SELECT TIMEOFDAY() INTO start_time;

EXECUTE FORMAT ('INSERT INTO expanded_radet.art_commencement_vitals_refresh
SELECT * from dblink(''db_link_ods'',
''SELECT DISTINCT ON (tvs.uuid, tvs.ods_datim_id) tvs.uuid, tvs.person_uuid,tvs.ods_datim_id,tvs.archived,
tvs.body_weight as baseLineWeight, tvs.height as baseLineHeight,
CONCAT(tvs.diastolic, '''' / '''', tvs.systolic) as baseLineBp, tvs.diastolic as diastolicBp,
tvs.systolic as systolicBp, clinical_stage.display as baseLineClinicalStage,
func_status.display as baseLineFunctionalStatus,
hv.description as firstRegimen, hrt.description as firstRegimenLine,
CASE WHEN hac.cd_4=0 THEN null ELSE hac.cd_4 END  AS baseLineCd4,
CASE WHEN hac.cd_4_percentage=0 THEN null ELSE hac.cd_4_percentage END AS cd4Percentage,
hac.visit_date as artStartDate
FROM (SELECT uuid, person_uuid, ods_datim_id,body_weight,height,diastolic, systolic, archived 
	 FROM ods_triage_vital_sign WHERE ods_load_time >= ''%L'') tvs
LEFT JOIN ods_hiv_art_clinical hac ON tvs.uuid=hac.vital_sign_uuid AND hac.person_uuid = tvs.person_uuid
LEFT JOIN ods_hiv_enrollment h ON hac.hiv_enrollment_uuid = h.uuid AND hac.ods_datim_id=h.ods_datim_id
LEFT JOIN ods_patient_person p ON p.uuid=h.person_uuid AND p.ods_datim_id=h.ods_datim_id
LEFT JOIN ods_hiv_regimen hv ON hv.id=hac.regimen_id AND hv.ods_datim_id=hac.ods_datim_id
LEFT JOIN ods_hiv_regimen_type hrt ON hrt.id=hac.regimen_type_id AND hrt.ods_datim_id=hac.ods_datim_id
LEFT JOIN ods_base_application_codeset clinical_stage ON clinical_stage.id=hac.clinical_stage_id AND clinical_stage.ods_datim_id=hac.ods_datim_id
LEFT JOIN ods_base_application_codeset func_status ON func_status.id=hac.functional_status_id AND func_status.ods_datim_id=hac.ods_datim_id
WHERE hac.is_commencement=true
-- AND hac.archived=0  AND h.archived=0 AND h.facility_id=1959
'')AS sm(uuid character varying,person_uuid character varying,ods_datim_id character varying(255),archived integer,
baselineweight double precision,baselineheight double precision,baselinebp text,diastolicbp double precision,
systolicbp double precision,baselineclinicalstage character varying,baselinefunctionalstatus character varying,
firstregimen character varying,firstregimenline character varying,baselinecd4 bigint,cd4percentage bigint,artstartdate date)

ON CONFLICT(uuid, person_uuid, ods_datim_id)
DO UPDATE SET
	baseLineHeight=EXCLUDED.baseLineHeight,
	baseLineBp=EXCLUDED.baseLineBp,
	diastolicBp=EXCLUDED.diastolicBp,
	systolicBp=EXCLUDED.systolicBp,
	baseLineClinicalStage=EXCLUDED.baseLineClinicalStage,
	baseLineFunctionalStatus=EXCLUDED.baseLineFunctionalStatus,
	firstRegimen=EXCLUDED.firstRegimen,
	firstRegimenLine=EXCLUDED.firstRegimenLine,
	baseLineCd4=EXCLUDED.baseLineCd4,
	cd4Percentage=EXCLUDED.cd4Percentage,
	artStartDate=EXCLUDED.artStartDate',
	last_load_end_time);

SELECT TIMEOFDAY() INTO end_time;

DELETE FROM expanded_radet.art_commencement_vitals_refresh
WHERE archived=1;

-- Count the number of rows inserted and updated
--SELECT COUNT(person_uuid90) INTO inserted_count
--FROM temp_upsert_laboatory_details_refresh
--WHERE NOT EXISTS (
--	SELECT 1
--	FROM expanded_radet.laboatory_details_refresh t
--	WHERE t.uuid = temp_upsert_laboatory_details_refresh.uuid
--	AND t.person_uuid90 = temp_upsert_laboatory_details_refresh.person_uuid90
--	AND t.cerv_ods_datim_id = temp_upsert_laboatory_details_refresh.cerv_ods_datim_id
--);

--SELECT COUNT(person_uuid90) INTO updated_count
--FROM temp_upsert_laboatory_details_refresh
--WHERE EXISTS (
--	SELECT 1
--	FROM expanded_radet.laboatory_details_refresh t
--	WHERE t.uuid = temp_upsert_laboatory_details_refresh.uuid
--	AND t.person_uuid90 = temp_upsert_laboatory_details_refresh.person_uuid90
--	AND t.cerv_ods_datim_id = temp_upsert_laboatory_details_refresh.cerv_ods_datim_id
--);

INSERT INTO public.streaming_remote_monitoring(table_name,start_time,load_end_time,record_count)
VALUES('art_commencement_vitals_refresh',start_time, end_time,record_count);

			 
END 
$$;


