--
-- Name: proc_upsert_arv_pharmacy(); Type: PROCEDURE; Schema: expanded_radet; Owner: lamisplus_etl
--

CREATE PROCEDURE expanded_radet.proc_upsert_arv_pharmacy()
    LANGUAGE plpgsql
    AS $$
DECLARE start_time TIMESTAMP;
DECLARE end_time TIMESTAMP;
DECLARE record_count bigint;
BEGIN

SELECT count(uuid) 
FROM expanded_radet.pharmacy_details_regimen
WHERE phar_details_regimen_load_time >=
(select MAX(load_end_time) 
 FROM public.streaming_remote_monitoring
WHERE table_name = 'arv_pharmacy_2nd_level_refresh')
INTO record_count;

SELECT TIMEOFDAY() INTO start_time;

INSERT INTO expanded_radet.arv_pharmacy
SELECT uuid, person_uuid40, pharma_ods_datim_id, dsdModel,visit_date as dateofStartofCurrentARTRegimen,
ods_hiv_regimen_description as currentARTRegimen,ods_hiv_regimen_type_description as currentRegimenLine,
p.next_appointment as nextPickupDate, 
CAST(CAST(refill_period AS INTEGER) / 30.0 AS DECIMAL(10, 1)) AS monthsOfARVRefill
FROM (SELECT uuid, person_uuid40, pharma_ods_datim_id, dsdmodel, visit_date, ods_hiv_regimen_description, 
	  ods_hiv_regimen_type_description, next_appointment, regimen_type_id, refill_period, 
	  phar_details_regimen_load_time 
	  FROM expanded_radet.pharmacy_details_regimen
	  WHERE phar_details_regimen_load_time >=
				   (select MAX(load_end_time) 
					FROM public.streaming_remote_monitoring
					WHERE table_name = 'arv_pharmacy_2nd_level_refresh')) p
WHERE regimen_type_id in (1, 2, 3, 4, 14) 
--AND p.archived = 0 
AND visit_date is not null
AND refill_period is not null 
AND ods_hiv_regimen_description IS NOT NULL
AND ods_hiv_regimen_type_description IS NOT NULL

ON CONFLICT(uuid,person_uuid40,pharma_ods_datim_id)
DO UPDATE SET
	dsdModel=EXCLUDED.dsdModel,
	dateofStartofCurrentARTRegimen=EXCLUDED.dateofStartofCurrentARTRegimen,
	currentARTRegimen=EXCLUDED.currentARTRegimen,
	currentRegimenLine=EXCLUDED.currentRegimenLine,
	nextPickupDate=EXCLUDED.nextPickupDate,
	monthsOfARVRefill=EXCLUDED.monthsOfARVRefill;

SELECT TIMEOFDAY() INTO end_time;

INSERT INTO public.streaming_remote_monitoring(table_name,start_time,load_end_time,record_count) 
			 VALUES ('arv_pharmacy_2nd_level_refresh',start_time, end_time, record_count);
			 
END $$;


ALTER PROCEDURE expanded_radet.proc_upsert_arv_pharmacy() OWNER TO lamisplus_etl;

--
-- Name: proc_upsert_base_biometric(); Type: PROCEDURE; Schema: expanded_radet; Owner: lamisplus_etl
--

CREATE PROCEDURE expanded_radet.proc_upsert_base_biometric()
    LANGUAGE plpgsql
    AS $$
DECLARE start_time TIMESTAMP;
DECLARE last_load_end_time TIMESTAMP;
DECLARE end_time TIMESTAMP;
DECLARE record_count bigint;
DECLARE inserted_count bigint;
DECLARE updated_count bigint;

BEGIN
-- Fetch the last load end time
SELECT MAX(load_end_time) 
INTO last_load_end_time
FROM streaming_remote_monitoring
WHERE table_name = 'base_biometric_refresh';

-- Fetch record count from the remote database using dblink
EXECUTE format(
	'SELECT *
	 FROM dblink(''db_link_ods'',
	 ''
	 SELECT count(person_uuid) 
	 FROM ods_biometric 
	 WHERE ods_load_time >= ''%L''			   
	'') 
	 AS sm(count bigint)',last_load_end_time) 
INTO record_count;

-- -- Use a temporary table to capture the rows affected by the upsert
-- CREATE TEMP TABLE temp_upsert_base_biometric (
-- 		personuuid character varying,
--         ods_datim_id character varying
--     );

SELECT TIMEOFDAY() INTO start_time;

EXECUTE FORMAT('INSERT INTO expanded_radet.base_biometric
SELECT * FROM dblink(''db_link_ods'',
''SELECT DISTINCT ON (person_uuid, ods_datim_id) person_uuid,ods_datim_id,recapture,archived,count,
			   MAX(enrollment_date) enrollment_date
FROM ods_biometric 
WHERE ods_load_time >= ''%L''
AND version_iso_20 is not null AND version_iso_20 is true 
--AND archived=0 
AND (recapture=0 or recapture is null)
GROUP BY 1,2,3,4,5'')
AS sm(person_uuid character varying,ods_datim_id character varying, 
	  recapture integer,archived integer,count bigint,enrollment_date date)
			   
ON CONFLICT (person_uuid, ods_datim_id)
DO NOTHING',
last_load_end_time);

SELECT TIMEOFDAY() INTO end_time;

DELETE FROM expanded_radet.base_biometric
WHERE archived=1;

UPDATE expanded_radet.base_biometric t1
SET facility_name=t2.facility_name, 
facility_state=t2.facility_state,
facility_lga=t2.facility_lga
FROM public.central_partner_mapping t2
WHERE t1.ods_datim_id=t2.datim_id
AND t1.facility_name IS NULL;

-- -- Count the number of rows inserted and updated
-- SELECT COUNT(person_uuid) INTO inserted_count
-- FROM temp_upsert_base_biometric
-- WHERE NOT EXISTS (
-- 	SELECT 1
-- 	FROM expanded_radet.cryptocol_antigen t
-- 	WHERE t.person_uuid = temp_upsert_base_biometric.person_uuid
-- 	AND t.ods_datim_id = temp_upsert_base_biometric.ods_datim_id
-- );

INSERT INTO public.streaming_remote_monitoring(table_name,start_time,load_end_time,record_count)
VALUES('base_biometric_refresh',start_time, end_time,record_count);
			 
END $$;


