	 SELECT count(id) 
	 FROM ods_base_application_codeset
	 WHERE ods_load_time >= ''%L''			   
	'') 
	 AS sm(count bigint)',last_load_end_time) 
INTO record_count;

CREATE TABLE IF NOT EXISTS expanded_radet.baseappcodeset_refresh(
id bigint,code character varying, codeset_group character varying,display character varying,
    language character varying,version character varying,
		ods_datim_id character varying(255),archived integer);
