	display=EXCLUDED.display,
	language=EXCLUDED.language,
	version=EXCLUDED.version',last_load_end_time);

SELECT TIMEOFDAY() INTO end_time;

INSERT INTO public.streaming_remote_monitoring(table_name,start_time,load_end_time,record_count)
VALUES('baseappcodeset_refresh',start_time, end_time,record_count);
			 
END 
$$;


