--
-- Name: proc_upsert_client_verification_refresh(); Type: PROCEDURE; Schema: expanded_radet; Owner: lamisplus_etl
--

CREATE PROCEDURE expanded_radet.proc_upsert_client_verification_refresh()
    LANGUAGE plpgsql
    AS $$
DECLARE start_time TIMESTAMP;
DECLARE last_load_end_time TIMESTAMP;
DECLARE end_time TIMESTAMP;
DECLARE record_count bigint;

BEGIN
-- Fetch the last load end time
SELECT MAX(load_end_time) 
INTO last_load_end_time
FROM streaming_remote_monitoring
WHERE table_name = 'client_verification_refresh';

-- Fetch record count from the remote database using dblink
EXECUTE FORMAT(
	'SELECT *
	 FROM dblink(''db_link_ods'',
	 ''
	 SELECT count(uuid) 
	 FROM ods_hiv_observation 
	 WHERE ods_load_time >= ''%L''			   
	'') 
	 AS sm(count bigint)',last_load_end_time) 
INTO record_count;

-- DROP TABLE IF EXISTS expanded_radet.client_verification_refresh;
CREATE TABLE IF NOT EXISTS expanded_radet.client_verification_refresh
(	uuid character varying,
    person_uuid character varying,
 	ods_datim_id character varying,
    date_of_observation date,
    archived integer,
    dateofattempt date,
    serialenrollmentno text,
    verificationattempts text,
    verificationstatus text,
    outcome text,
    comment text,
    returnedtocare text,
    referredto text,
    discontinuation text,
    dateofdiscontinuation text,
    noinitbiometric text,
    duplicateddemographic text,
    norecapture text,
    lastvisitisover18m text,
    incompletevisitdata text,
    repeatencounternoprint text,
    longintervalsarvpickup text,
    samesexdobartstartdate text,
    pickupbyproxy text,
    otherspecifyforcv text,
	facility_name character varying,
	state character varying,
	lga character varying,
 	noAttempts bigint,
	anyOfTheFollowingList text,
	CONSTRAINT unq_uuidpersondatim_clientverificationrefresh
	UNIQUE (uuid,person_uuid, ods_datim_id)
);

CREATE INDEX IF NOT EXISTS idx_datimdateofobservation_clientverificationrefresh ON 
expanded_radet.client_verification_refresh(ods_datim_id,date_of_observation);

SELECT TIMEOFDAY() INTO start_time;

EXECUTE FORMAT('INSERT INTO expanded_radet.client_verification_refresh
SELECT clr.uuid, clr.person_uuid, clr.ods_datim_id, clr.date_of_observation,
clr.archived, clr.dateofattempt, clr.serialenrollmentno, clr.verificationattempts,
clr.verificationstatus, clr.outcome, clr.comment, 
clr.returnedtocare returnedtocare, clr.referredto,
clr.discontinuation, clr.dateofdiscontinuation, clr.noinitbiometric,
clr.duplicateddemographic, clr.norecapture, clr.lastvisitisover18m,
clr.incompletevisitdata, clr.repeatencounternoprint,
clr.longintervalsarvpickup, clr.samesexdobartstartdate,
clr.pickupbyproxy, clr.otherspecifyforcv, cpm.facility_name,
cpm.facility_state state, cpm.facility_lga lga,clr.noattempts,clr.anyOfTheFollowingList
FROM (
SELECT * FROM dblink(''db_link_ods'',
''SELECT h.uuid,h.person_uuid,h.ods_datim_id, h.date_of_observation, h.archived,
CAST(h.data->''''attempt''''->0->>''''dateOfAttempt'''' AS DATE) AS dateOfAttempt,
h.data->>''''serialEnrollmentNo'''' AS serialEnrollmentNo, 
h.data->''''attempt''''->0->>''''verificationAttempts'''' AS verificationAttempts, 
h.data->''''attempt''''->0->>''''verificationStatus'''' AS verificationStatus, 
h.data->''''attempt''''->0->>''''outcome'''' AS outcome, 
h.data->''''attempt''''->0->>''''comment'''' AS comment, 
(CASE WHEN h.data->>''''returnedToCare''''='''''''' OR h.data->>''''returnedToCare''''='''' ''''
THEN NULL ELSE CAST(h.data->>''''returnedToCare'''' AS DATE) END) AS returnedToCare, 
h.data->>''''referredTo'''' AS referredTo, 
h.data->>''''discontinuation'''' AS discontinuation, 
h.data->>''''dateOfDiscontinuation'''' AS dateOfDiscontinuation, 
MAX(CASE WHEN ''''No initial fingerprint was captured'''' IN (SELECT jsonb_array_elements_text(h.data->''''anyOfTheFollowing'''')) THEN ''''YES'''' ELSE ''''NO'''' END) AS noInitBiometric,
MAX(CASE WHEN ''''Duplicated demographic and clinical variables'''' IN (SELECT jsonb_array_elements_text(h.data->''''anyOfTheFollowing'''')) THEN ''''YES'''' ELSE ''''NO'''' END) AS duplicatedDemographic,
MAX(CASE WHEN ''''Records of repeated clinical encounters, with no fingerprint recapture.'''' IN (SELECT jsonb_array_elements_text(h.data->''''anyOfTheFollowing'''')) THEN ''''YES'''' ELSE ''''NO'''' END) AS noRecapture,
MAX(CASE WHEN ''''Last clinical visit is over 15 months prior'''' IN (SELECT jsonb_array_elements_text(h.data->''''anyOfTheFollowing'''')) THEN ''''YES'''' ELSE ''''NO'''' END) AS lastVisitIsOver18M,
MAX(CASE WHEN ''''Incomplete visit data on the care card or pharmacy forms or EMR '''' IN (SELECT jsonb_array_elements_text(h.data->''''anyOfTheFollowing'''')) THEN ''''YES'''' ELSE ''''NO'''' END) AS incompleteVisitData,
MAX(CASE WHEN ''''Records with same services e.g ART start date and at least 3 consecutive last ART pickup dats, VL result etc'''' IN (SELECT jsonb_array_elements_text(h.data->''''anyOfTheFollowing'''')) THEN ''''YES'''' ELSE ''''NO'''' END) AS repeatEncounterNoPrint,
MAX(CASE WHEN ''''Long intervals between ARV pick-ups (pick-ups more than one year apart in the same facility)'''' IN (SELECT jsonb_array_elements_text(h.data->''''anyOfTheFollowing'''')) THEN ''''YES'''' ELSE ''''NO'''' END) AS longIntervalsARVPickup,
MAX(CASE WHEN ''''Same sex, DOB and ART start date'''' IN (SELECT jsonb_array_elements_text(h.data->''''anyOfTheFollowing'''')) THEN ''''YES'''' ELSE ''''NO'''' END) AS sameSexDOBARTStartDate,
MAX(CASE WHEN ''''Consistently had drug pickup by proxy without viral load sample collection for two quarters'''' IN (SELECT jsonb_array_elements_text(h.data->''''anyOfTheFollowing'''')) THEN ''''YES'''' ELSE ''''NO'''' END) AS pickupByProxy,
MAX(CASE WHEN ''''Others'''' IN (SELECT jsonb_array_elements_text(h.data->''''anyOfTheFollowing'''')) THEN ''''YES'''' ELSE ''''NO'''' END) AS otherSpecifyForCV,
COUNT(uuid) noattempts,
COALESCE(string_agg(CAST(any_element.value AS text), '''', ''''), '''''''') AS anyOfTheFollowingList
FROM (SELECT uuid,person_uuid,ods_datim_id,date_of_observation,data,type,archived
	  FROM ods_hiv_observation WHERE ods_load_time>''%L'') h
LEFT JOIN jsonb_array_elements_text(h.data->''''anyOfTheFollowing'''') any_element ON true
WHERE h.type = ''''Client Verification''''
GROUP BY uuid, person_uuid,ods_datim_id, date_of_observation, archived, h.data
'')AS sm(uuid character varying,person_uuid character varying,ods_datim_id character varying,
		date_of_observation date,archived integer,dateofattempt date,serialenrollmentno text,
		verificationattempts text,verificationstatus text,outcome text,comment text,
		returnedtocare date,referredto text,discontinuation text,dateofdiscontinuation text,
		noinitbiometric text,duplicateddemographic text,norecapture text,lastvisitisover18m text,
		incompletevisitdata text,repeatencounternoprint text,longintervalsarvpickup text,
		samesexdobartstartdate text,pickupbyproxy text,otherspecifyforcv text,noattempts bigint,
		anyOfTheFollowingList text)) clr
LEFT JOIN central_partner_mapping cpm ON clr.ods_datim_id=cpm.datim_id
ON CONFLICT(uuid,person_uuid,ods_datim_id)
DO UPDATE SET
	date_of_observation=EXCLUDED.date_of_observation,
	archived=EXCLUDED.archived,
	dateofattempt=EXCLUDED.dateofattempt,
	serialenrollmentno=EXCLUDED.serialenrollmentno,
	verificationattempts=EXCLUDED.verificationattempts,
	verificationstatus=EXCLUDED.verificationstatus,
	outcome=EXCLUDED.outcome,
	comment=EXCLUDED.comment,
	returnedtocare=EXCLUDED.returnedtocare,
	referredto=EXCLUDED.referredto,
	discontinuation=EXCLUDED.discontinuation,
	dateofdiscontinuation=EXCLUDED.dateofdiscontinuation,
	noinitbiometric=EXCLUDED.noinitbiometric,
	duplicateddemographic=EXCLUDED.duplicateddemographic,
	norecapture=EXCLUDED.norecapture,
	lastvisitisover18m=EXCLUDED.lastvisitisover18m,
	incompletevisitdata=EXCLUDED.incompletevisitdata,
	repeatencounternoprint=EXCLUDED.repeatencounternoprint,
	longintervalsarvpickup=EXCLUDED.longintervalsarvpickup,
	samesexdobartstartdate=EXCLUDED.samesexdobartstartdate,
	pickupbyproxy=EXCLUDED.pickupbyproxy,
	otherspecifyforcv=EXCLUDED.otherspecifyforcv,
	anyOfTheFollowingList=EXCLUDED.anyOfTheFollowingList',last_load_end_time);

UPDATE expanded_radet.client_verification_refresh cvr
SET noattempts=c.count
FROM (SELECT * FROM dblink('db_link_ods',
'SELECT person_uuid AS count_person_uuid, ods_datim_id AS count_ods_datim_id,
COUNT(person_uuid)count
FROM ods_hiv_observation WHERE type = ''Client Verification''
GROUP BY person_uuid, ods_datim_id') 
AS sm(count_person_uuid character varying,count_ods_datim_id character varying,
	 count bigint))c 
WHERE c.count_person_uuid = cvr.person_uuid and cvr.ods_datim_id= c.count_ods_datim_id;

SELECT TIMEOFDAY() INTO end_time;

DELETE FROM expanded_radet.client_verification_refresh
WHERE archived=1;

INSERT INTO public.streaming_remote_monitoring(table_name,start_time,load_end_time,record_count)
VALUES('client_verification_refresh',start_time, end_time,record_count);
		 
END 
$$;


ALTER PROCEDURE expanded_radet.proc_upsert_client_verification_refresh() OWNER TO lamisplus_etl;

--
-- Name: proc_upsert_clinic_data_old_refresh(); Type: PROCEDURE; Schema: expanded_radet; Owner: lamisplus_etl
--

CREATE PROCEDURE expanded_radet.proc_upsert_clinic_data_old_refresh()
    LANGUAGE plpgsql
    AS $_$
DECLARE start_time TIMESTAMP;
DECLARE last_load_end_time TIMESTAMP;
DECLARE end_time TIMESTAMP;
DECLARE record_count bigint;

BEGIN

-- Fetch the last load end time
SELECT MAX(load_end_time) 
INTO last_load_end_time
FROM streaming_remote_monitoring
WHERE table_name = 'clinic_data_refresh';

-- Fetch record count from the remote database using dblink
EXECUTE FORMAT(
	'SELECT *
	 FROM dblink(''db_link_ods'',
	 ''
	 SELECT count(uuid) 
	 FROM ods_patient_person 
	 WHERE ods_load_time >= ''%L''			   
	'') 
	 AS sm(count bigint)',last_load_end_time) 
INTO record_count;

-- Use a temporary table to capture the rows affected by the upsert
--CREATE TEMP TABLE temp_upsert_clinic_data_refresh (
  --      patientuuid character varying,
    --    patient_person_datim_id character varying
   -- );
	
SELECT TIMEOFDAY() INTO start_time;

EXECUTE FORMAT ('INSERT INTO expanded_radet.clinic_data_refresh
SELECT * from dblink(''db_link_ods'',
''SELECT DISTINCT ON (p.uuid, p.ods_datim_id) p.uuid AS patientId,p.ods_datim_id patient_person_datim_id,
p.hospital_number AS hospitalNumber,INITCAP(p.sex) AS gender,p.date_of_birth AS dateOfBirth,p.archived,
facility.facility_name AS facilityName,facility.facility_lga AS lga,facility.facility_state AS state,
tvs.facility_id,tvs.body_weight as BodyWeight,
(CASE
WHEN hac.pregnancy_status = ''''Not Pregnant'''' THEN hac.pregnancy_status
WHEN hac.pregnancy_status = ''''Pregnant'''' THEN hac.pregnancy_status
WHEN hac.pregnancy_status = ''''Breastfeeding'''' THEN hac.pregnancy_status
WHEN hac.pregnancy_status = ''''Post Partum'''' THEN hac.pregnancy_status
WHEN preg.display IS NOT NULL THEN hac.pregnancy_status
ELSE NULL END ) AS pregnancyStatus,hac.next_appointment as nextAppointment,hac.visit_date as visitDate, 
funStatus.display as funtionalStatus,clnicalStage.display as clinicalStage,tbStatus.display as tbStatus,
tvs.archived AS ods_triage_vital_sign_archived,
hac.archived AS ods_hiv_art_clinical_archived,
tvs.diastolic,
tvs.systolic,
tvs.height,
CONCAT(tvs.systolic, ''''/'''', tvs.diastolic) AS bp,
CASE WHEN trim(hac.tb_screen->>''''tbStatusId'''') <> '''''''' AND hac.tb_screen->>''''tbStatusId'''' ~ ''''^\d+$''''
THEN CAST(hac.tb_screen->>''''tbStatusId'''' as bigint) ELSE NULL END AS tb_status_id
FROM (SELECT uuid,ods_datim_id,hospital_number,sex,facility_id,date_of_birth,archived
		FROM ods_patient_person WHERE ods_load_time >= ''%L'') p 
LEFT JOIN central_partner_mapping facility ON p.ods_datim_id=facility.datim_id
LEFT JOIN ods_hiv_art_clinical hac ON hac.person_uuid = p.uuid AND hac.ods_datim_id=p.ods_datim_id
LEFT JOIN ods_base_application_codeset preg ON preg.code = hac.pregnancy_status 
AND hac.ods_datim_id=preg.ods_datim_id
LEFT JOIN ods_base_application_codeset funStatus ON funStatus.id = hac.functional_status_id
AND hac.ods_datim_id=funStatus.ods_datim_id
LEFT JOIN ods_base_application_codeset clnicalStage ON clnicalStage.id = hac.clinical_stage_id 
AND hac.ods_datim_id=clnicalStage.ods_datim_id
LEFT JOIN ods_base_application_codeset tbStatus ON tbStatus.id = CAST(regexp_replace(hac.tb_status, ''''[^0-9]'''', '''''''', ''''g'''') AS INTEGER)    
AND hac.ods_datim_id=tbStatus.ods_datim_id
LEFT JOIN ods_triage_vital_sign tvs ON tvs.uuid = hac.vital_sign_uuid AND hac.ods_datim_id=tvs.ods_datim_id
--WHERE hac.archived = 0 
'')AS sm(patientid character varying,patient_person_datim_id character varying(255),hospitalnumber character varying,gender text,
		dateofbirth date,archived integer,facilityname character varying,lga character varying,state character varying,facility_id bigint,
		bodyweight double precision,pregnancystatus character varying,nextappointment date,visitdate date,funtionalstatus character varying,
		clinicalstage character varying,tbstatus character varying,ods_triage_vital_sign_archived integer,ods_hiv_art_clinical_archived integer,
		diastolic double precision,systolic double precision,height double precision,bp text,tb_status_id bigint)
ON CONFLICT(patientid,patient_person_datim_id)
DO UPDATE SET
	archived=EXCLUDED.archived,
	facilityname=EXCLUDED.facilityname,
	lga=EXCLUDED.lga,
	state=EXCLUDED.state,
	facility_id=EXCLUDED.facility_id,
	bodyweight=EXCLUDED.bodyweight,
	pregnancystatus=EXCLUDED.pregnancystatus,
	nextappointment=EXCLUDED.nextappointment,
	visitdate=EXCLUDED.visitdate,
	funtionalstatus=EXCLUDED.funtionalstatus,
	clinicalstage=EXCLUDED.clinicalstage,
	tbstatus=EXCLUDED.tbstatus,
	ods_triage_vital_sign_archived=EXCLUDED.ods_triage_vital_sign_archived,
	ods_hiv_art_clinical_archived=EXCLUDED.ods_hiv_art_clinical_archived,
	diastolic=EXCLUDED.diastolic,
	systolic=EXCLUDED.systolic,
	height=EXCLUDED.height,
	bp=EXCLUDED.bp,
    tb_status_id=EXCLUDED.tb_status_id',
	last_load_end_time);	
		
SELECT TIMEOFDAY() INTO end_time;

DELETE FROM expanded_radet.clinic_data_refresh
WHERE archived=1;

-- Count the number of rows inserted and updated
--SELECT COUNT(patientuuid) INTO inserted_count
--FROM temp_upsert_clinic_data_refresh
--WHERE NOT EXISTS (
--	SELECT 1
--	FROM expanded_radet.clinic_data_refresh t
--	WHERE t.uuid = temp_upsert_clinic_data_refresh.uuid
--	AND t.patientuuid = temp_upsert_clinic_data_refresh.patientuuid
--	AND t.cerv_ods_datim_id = temp_upsert_clinic_data_refresh.cerv_ods_datim_id
--);

--SELECT COUNT(patientuuid) INTO updated_count
--FROM temp_upsert_clinic_data_refresh
--WHERE EXISTS (
--	SELECT 1
--	FROM expanded_radet.clinic_data_refresh t
--	WHERE t.uuid = temp_upsert_clinic_data_refresh.uuid
--	AND t.patientuuid = temp_upsert_clinic_data_refresh.patientuuid
--	AND t.cerv_ods_datim_id = temp_upsert_clinic_data_refresh.cerv_ods_datim_id
--);

INSERT INTO public.streaming_remote_monitoring(table_name,start_time,load_end_time,record_count)
VALUES('clinic_data_refresh',start_time, end_time,record_count);

			 
END 
$_$;


