--
-- Name: proc_upsert_hiv_clinical_enrollment_refresh(); Type: PROCEDURE; Schema: expanded_radet; Owner: lamisplus_etl
--

CREATE PROCEDURE expanded_radet.proc_upsert_hiv_clinical_enrollment_refresh()
    LANGUAGE plpgsql
    AS $$
DECLARE start_time TIMESTAMP;
DECLARE last_load_end_time TIMESTAMP;
DECLARE end_time TIMESTAMP;
DECLARE record_count bigint;

BEGIN

-- Fetch the last load end time
SELECT MAX(load_end_time) 
INTO last_load_end_time
FROM streaming_remote_monitoring
WHERE table_name = 'hiv_clinical_enrollment_refresh';

-- Fetch record count from the remote database using dblink
EXECUTE FORMAT(
	'SELECT *
	 FROM dblink(''db_link_ods'',
	 ''
	 SELECT count(uuid) 
	 FROM ods_hiv_art_clinical 
	 WHERE ods_load_time >= ''%L''			   
	'') 
	 AS sm(count bigint)',last_load_end_time) 
INTO record_count;

-- DROP TABLE IF EXISTS expanded_radet.hiv_clinical_enrollment_refresh;
CREATE TABLE IF NOT EXISTS expanded_radet.hiv_clinical_enrollment_refresh(
person_uuid character varying,ods_datim_id character varying(255),tb_status character varying,
pregnancy_status character varying,clinical_stage_id bigint,vital_sign_uuid character varying,
dateOfTbScreened1 date,load_end_time timestamp);
-- ALTER TABLE expanded_radet.hiv_clinical_enrollment_refresh
-- ADD CONSTRAINT unq_hiv_clinical_enrollment_refresh UNIQUE (person_uuid,ods_datim_id);
CREATE INDEX IF NOT EXISTS idx_personuuiddatimid_hiv_clinicalenrollment_refresh
ON expanded_radet.hiv_clinical_enrollment_refresh(person_uuid,ods_datim_id);
CREATE INDEX IF NOT EXISTS idx_vitalsignuuiddatimid_hivclinical_enrollment_refresh 
ON expanded_radet.hiv_clinical_enrollment_refresh(vital_sign_uuid,ods_datim_id);
CREATE INDEX IF NOT EXISTS idx_clinicalstageiddatimid_hivclinical_enrollment_refresh 
ON expanded_radet.hiv_clinical_enrollment_refresh(clinical_stage_id,ods_datim_id);
CREATE INDEX IF NOT EXISTS idx_pregnancystatusdatimid_hiv_clinical_enrollment_refresh 
ON expanded_radet.hiv_clinical_enrollment_refresh(pregnancy_status,ods_datim_id);
CREATE INDEX IF NOT EXISTS idx_tbstatusdatimid_hiv_clinical_enrollment_refresh 
ON expanded_radet.hiv_clinical_enrollment_refresh(tb_status,ods_datim_id);
CREATE INDEX IF NOT EXISTS brinidx_loaendtime_hiv_clinical_enrollment_refresh 
ON expanded_radet.hiv_clinical_enrollment_refresh USING brin (load_end_time);

SELECT TIMEOFDAY() INTO start_time;

EXECUTE FORMAT ('INSERT INTO expanded_radet.hiv_clinical_enrollment_refresh
SELECT * from dblink(''db_link_ods'',
''SELECT DISTINCT ON (hac.person_uuid,hac.ods_datim_id) hac.person_uuid,hac.ods_datim_id,
	hac.tb_status,hac.pregnancy_status,hac.clinical_stage_id,hac.vital_sign_uuid,
CASE WHEN hac.tb_screen IS NOT NULL THEN CAST(hac.visit_date AS DATE) ELSE NULL END AS dateOfTbScreened1,
TIMEOFDAY() AS load_end_time
FROM (SELECT person_uuid,ods_datim_id,tb_screen,tb_status,pregnancy_status,
	clinical_stage_id,visit_date,vital_sign_uuid,archived
		FROM ods_hiv_art_clinical WHERE ods_load_time > ''%L'') hac 
INNER JOIN ods_hiv_enrollment he ON he.person_uuid = hac.person_uuid AND he.ods_datim_id = hac.ods_datim_id
WHERE hac.archived = 0 AND he.archived = 0
'')AS sm(person_uuid character varying,ods_datim_id character varying(255),tb_status character varying,
		pregnancy_status character varying,clinical_stage_id bigint,vital_sign_uuid character varying,
		dateOfTbScreened1 date,load_end_time timestamp)
ON CONFLICT(person_uuid,ods_datim_id)
DO UPDATE SET
	tb_status=EXCLUDED.tb_status,
	pregnancy_status=EXCLUDED.pregnancy_status,
	dateOfTbScreened1=EXCLUDED.dateOfTbScreened1',last_load_end_time);

SELECT TIMEOFDAY() INTO end_time;

INSERT INTO public.streaming_remote_monitoring(table_name,start_time,load_end_time,record_count)
VALUES('hiv_clinical_enrollment_refresh',start_time, end_time,record_count);
			 
END 
$$;


