		hst.ods_datim_id,hst.status_date,hst.cause_of_death,hst.va_cause_of_death,hst.hiv_status,
		hst.archived, he.person_uuid hiv_enrollment_uuid
FROM (SELECT uuid,person_id,ods_datim_id,status_date,cause_of_death,va_cause_of_death,
	  hiv_status,archived FROM ods_hiv_status_tracker
	  WHERE ods_load_time >= ''%L'') hst
LEFT JOIN ods_hiv_enrollment he ON he.person_uuid = hst.person_id AND he.ods_datim_id = hst.ods_datim_id		
'')AS sm(uuid character varying,person_id character varying, ods_datim_id character varying(255),
		status_date date,cause_of_death character varying,va_cause_of_death character varying,
		 hiv_status character varying, archived integer,hiv_enrollment_uuid character varying)
ON CONFLICT(uuid, ods_datim_id)
DO UPDATE SET
	status_date=EXCLUDED.status_date,
	cause_of_death=EXCLUDED.cause_of_death,
	va_cause_of_death=EXCLUDED.va_cause_of_death,
	hiv_status=EXCLUDED.hiv_status,
	archived=EXCLUDED.archived',
last_load_end_time);

SELECT TIMEOFDAY() INTO end_time;

DELETE FROM expanded_radet.hiv_status_tracker_refresh
WHERE archived=1;

INSERT INTO public.streaming_remote_monitoring(table_name,start_time,load_end_time,record_count)
VALUES('hiv_status_tracker_refresh',start_time, end_time,record_count);

			 
END 
$$;


