-- Name: proc_upsert_hivclinicalenrollment_baseappcode_refresh(); Type: PROCEDURE; Schema: expanded_radet; Owner: lamisplus_etl
--

CREATE PROCEDURE expanded_radet.proc_upsert_hivclinicalenrollment_baseappcode_refresh()
    LANGUAGE plpgsql
    AS $$
DECLARE start_time TIMESTAMP;
DECLARE last_load_end_time TIMESTAMP;
DECLARE end_time TIMESTAMP;
DECLARE record_count bigint;

BEGIN

-- Fetch the last load end time
SELECT MAX(load_end_time) 
INTO last_load_end_time
FROM streaming_remote_monitoring
WHERE table_name = 'hivclinicalenrollment_baseappcode_refresh';

-- Fetch record count from the remote database using dblink
SELECT count(person_uuid) INTO record_count
 FROM expanded_radet.hiv_clinical_enrollment_refresh 
 WHERE load_end_time >= last_load_end_time;

CREATE TABLE IF NOT EXISTS expanded_radet.hivclinicalenrollment_baseappcode_refresh(
person_uuid character varying, vital_sign_uuid character varying,ods_datim_id character varying,
currentClinicalStage character varying,tbStatus1 character varying,pregnancyStatus character varying, 
dateOfTbScreened1 date
);
-- ALTER TABLE expanded_radet.hivclinicalenrollment_baseappcode_refresh
-- ADD CONSTRAINT unq_hivclinicalenrollment_baseappcode_refresh UNIQUE (person_uuid,vital_sign_uuid,ods_datim_id);

CREATE INDEX IF NOT EXISTS ipersonuuiddatim_clinicenrollment_baseappcode_refresh
ON expanded_radet.hivclinicalenrollment_baseappcode_refresh(person_uuid,ods_datim_id);

SELECT TIMEOFDAY() INTO start_time;

INSERT INTO expanded_radet.hivclinicalenrollment_baseappcode_refresh
SELECT hac.person_uuid, hac.vital_sign_uuid,hac.ods_datim_id,bac.display AS currentClinicalStage,
tbs.display AS tbStatus1, (CASE WHEN preg.display IS NOT NULL THEN preg.display 
 ELSE hac.pregnancy_status END) AS pregnancyStatus, hac.dateOfTbScreened1
FROM (SELECT person_uuid,ods_datim_id, vital_sign_uuid, pregnancy_status,clinical_stage_id,
	  tb_status,dateOfTbScreened1
	  FROM expanded_radet.hiv_clinical_enrollment_refresh
	 WHERE load_end_time > last_load_end_time) hac
LEFT JOIN expanded_radet.baseappcodeset_refresh bac ON bac.id = hac.clinical_stage_id AND bac.ods_datim_id = hac.ods_datim_id
LEFT JOIN expanded_radet.baseappcodeset_refresh preg ON preg.code = hac.pregnancy_status AND preg.ods_datim_id = hac.ods_datim_id
LEFT JOIN expanded_radet.baseappcodeset_refresh tbs ON tbs.id = CAST(hac.tb_status AS INTEGER) AND tbs.ods_datim_id = hac.ods_datim_id
ON CONFLICT(person_uuid,vital_sign_uuid,ods_datim_id)
DO UPDATE SET
	currentClinicalStage=EXCLUDED.currentClinicalStage,
	tbStatus1=EXCLUDED.tbStatus1,
	pregnancyStatus=EXCLUDED.pregnancyStatus,
	dateOfTbScreened1=EXCLUDED.dateOfTbScreened1;

SELECT TIMEOFDAY() INTO end_time;

INSERT INTO public.streaming_remote_monitoring(table_name,start_time,load_end_time,record_count)
VALUES('hivclinicalenrollment_baseappcode_refresh',start_time, end_time,record_count);
			 
END $$;


