--
-- Name: proc_upsert_lab_test_results_refresh(); Type: PROCEDURE; Schema: expanded_radet; Owner: lamisplus_etl
--

CREATE PROCEDURE expanded_radet.proc_upsert_lab_test_results_refresh()
    LANGUAGE plpgsql
    AS $$
DECLARE start_time TIMESTAMP;
DECLARE last_load_end_time TIMESTAMP;
DECLARE end_time TIMESTAMP;
DECLARE record_count bigint;
DECLARE partitioned_name TEXT;
DECLARE test_name TEXT;
DECLARE lab_test_id BIGINT;

BEGIN

SELECT partition_name 
INTO partitioned_name
FROM public.lab_test_name
WHERE is_selected;

SELECT id 
INTO lab_test_id
FROM public.lab_test_name
WHERE is_selected;

SELECT lab_test_name 
INTO test_name
FROM public.lab_test_name
WHERE is_selected;

-- Fetch the last load end time
SELECT MIN(load_end_time) 
INTO last_load_end_time
FROM streaming_remote_monitoring
WHERE table_name = 'lab_test_results_refresh';

-- Fetch record count from the remote database using dblink
EXECUTE FORMAT(
	'SELECT *
	 FROM dblink(''db_link_ods'',
	 ''
	 SELECT count(uuid) 
	 FROM ods_laboratory_test 
	 WHERE ods_load_time >= ''%L''			   
	'') 
	 AS sm(count bigint)',last_load_end_time) 
INTO record_count;

-- DROP TABLE IF EXISTS expanded_radet.lab_test_results_refresh;
-- CREATE TABLE IF NOT EXISTS expanded_radet.lab_test_results_refresh
-- (	id bigint,
--     uuid character varying,
--     lab_order_id integer,
--     patient_uuid character varying,
--     ods_datim_id character varying(255),
--     test character varying,
--     date_sample_collected date,
--     result character varying,
--     date_result_reported date,
--     archived integer,
--     viral_load_indication integer,
--     load_end_time timestamp without time zone,
--     CONSTRAINT unq_uuidlaborderidtestpatientdatim UNIQUE (id,ods_datim_id,test),
--     CONSTRAINT labtest_partition_key_check CHECK (test IS NOT NULL)
-- ) PARTITION BY LIST (test);

-- CREATE INDEX IF NOT EXISTS idx_patientuuiddatim_lab_test_results ON 
-- expanded_radet.lab_test_results_refresh(patient_uuid,ods_datim_id);

-- Assuming partitioned_name = 'Cytology'
-- DROP TABLE IF EXISTS expanded_radet."lab_test_results_refresh_Cytology"
EXECUTE FORMAT(
    'CREATE TABLE IF NOT EXISTS expanded_radet.%I
     PARTITION OF expanded_radet.lab_test_results_refresh
     FOR VALUES IN (%L)', partitioned_name, test_name);

SELECT TIMEOFDAY() INTO start_time;

EXECUTE FORMAT ('INSERT INTO expanded_radet.lab_test_results_refresh
SELECT * from dblink(''db_link_ods'',
''SELECT DISTINCT ON (lt.id,lt.ods_datim_id) lt.id, lt.uuid,
lt.lab_order_id, lt.patient_uuid, lt.ods_datim_id,ll.lab_test_name AS test,
CAST(ls.date_sample_collected AS DATE) AS date_sample_collected,
lr.result_reported AS result,CAST(lr.date_result_reported AS DATE) AS date_result_reported,
lt.archived,lt.viral_load_indication, TIMEOFDAY() load_end_time
FROM (SELECT id,uuid,lab_order_id,lab_test_id,patient_uuid,ods_datim_id,
		viral_load_indication,archived 
		FROM ods_laboratory_test WHERE ods_load_time >= ''%L'' 
		AND lab_test_id=''%L'' AND lab_test_id IS NOT NULL AND archived=0) lt
LEFT JOIN (SELECT id,ods_datim_id,lab_test_name 
		  FROM ods_laboratory_labtest WHERE id = ''%L'') ll 
ON ll.id = lt.lab_test_id AND ll.ods_datim_id = lt.ods_datim_id
LEFT JOIN ods_laboratory_sample ls ON ls.test_id = lt.id AND ls.patient_uuid = lt.patient_uuid 
AND ls.ods_datim_id=lt.ods_datim_id AND ls.archived=0
LEFT JOIN ods_laboratory_result lr ON lr.test_id = lt.id AND lr.patient_uuid = lt.patient_uuid 
AND lr.ods_datim_id=lt.ods_datim_id AND lr.archived=0
'')AS sm(id bigint, uuid character varying, lab_order_id integer,patient_uuid character varying,
	ods_datim_id character varying(255),test character varying,date_sample_collected date,
	result character varying,date_result_reported date,archived integer,
	viral_load_indication integer, load_end_time timestamp)
		
ON CONFLICT(id,ods_datim_id,test)
DO UPDATE SET
	test=EXCLUDED.test,
	--indication=EXCLUDED.indication,
	date_sample_collected=EXCLUDED.date_sample_collected,
	result=EXCLUDED.result,
	date_result_reported=EXCLUDED.date_result_reported,
	archived=EXCLUDED.archived,
	viral_load_indication=EXCLUDED.viral_load_indication,
	load_end_time=EXCLUDED.load_end_time',
	last_load_end_time,lab_test_id,lab_test_id);

SELECT TIMEOFDAY() INTO end_time;

DELETE FROM expanded_radet.lab_test_results_refresh
WHERE archived=1;

-- INSERT INTO public.streaming_remote_monitoring(table_name,start_time,load_end_time,record_count)
-- VALUES('lab_test_results_refresh',start_time, end_time,record_count);

END 
$$;


ALTER PROCEDURE expanded_radet.proc_upsert_lab_test_results_refresh() OWNER TO lamisplus_etl;

--
-- Name: proc_upsert_laboratory_details_refresh(); Type: PROCEDURE; Schema: expanded_radet; Owner: lamisplus_etl
--

CREATE PROCEDURE expanded_radet.proc_upsert_laboratory_details_refresh()
    LANGUAGE plpgsql
    AS $$
DECLARE start_time TIMESTAMP;
DECLARE last_load_end_time TIMESTAMP;
DECLARE end_time TIMESTAMP;
DECLARE record_count bigint;

BEGIN

-- Fetch the last load end time
SELECT MAX(load_end_time) 
INTO last_load_end_time
FROM streaming_remote_monitoring
WHERE table_name = 'laboratory_details_refresh';

-- Fetch record count from the remote database using dblink
SELECT count(uuid) 
	 FROM expanded_radet.laboratoryorder_hivenrollment_refresh
	 WHERE load_end_time >= last_load_end_time
INTO record_count;

SELECT TIMEOFDAY() INTO start_time;

-- SELECT * FROM expanded_radet.laboratorytest_labtest_sample_results_refresh

INSERT INTO expanded_radet.laboratory_details_refresh
SELECT DISTINCT ON (lo.uuid,lo.patient_uuid,lo.ods_datim_id) lo.uuid,
lo.patient_uuid AS person_uuid,lo.ods_datim_id,lt.test,lt.indication,
lt.date_sample_collected, lt.result,lt.date_result_reported,lo.laboratory_order_date,
lo.archived lab_order_archived,opp.hospitalnumber,lo.hiv_enrollment_archived,
opp.ods_patient_person_archived patient_person_archived,
cpm.facility_name, cpm.facility_state state, cpm.facility_lga lga,
cpm.ip_name
FROM (SELECT id,uuid,patient_uuid,ods_datim_id,laboratory_order_date,
	  archived,hiv_enrollment_archived
	 FROM expanded_radet.laboratoryorder_hivenrollment_refresh
	 WHERE load_end_time >= last_load_end_time) lo
LEFT JOIN expanded_radet.patient_bio_data opp ON opp.personuuid=lo.patient_uuid 
AND opp.bio_ods_datim_id=lo.ods_datim_id
LEFT JOIN expanded_radet.sub_laboratory_details_refresh lt ON lt.lab_order_id = lo.id 
AND lt.patient_uuid=lo.patient_uuid AND lt.ods_datim_id=lo.ods_datim_id
LEFT JOIN public.central_partner_mapping cpm ON cpm.datim_id=lo.ods_datim_id
ON CONFLICT(uuid, person_uuid, ods_datim_id)
DO UPDATE SET
	test=EXCLUDED.test,
	indication=EXCLUDED.indication,
	date_sample_collected=EXCLUDED.date_sample_collected,
	result=EXCLUDED.result,
	date_result_reported=EXCLUDED.date_result_reported,
	laboratory_order_date=EXCLUDED.laboratory_order_date,
	lab_order_archived=EXCLUDED.lab_order_archived,
	hospitalnumber=EXCLUDED.hospitalnumber,
	hiv_enrollment_archived=EXCLUDED.hiv_enrollment_archived,
	patient_person_archived=EXCLUDED.patient_person_archived;

SELECT TIMEOFDAY() INTO end_time;

INSERT INTO public.streaming_remote_monitoring(table_name,start_time,load_end_time,record_count)
VALUES('laboratory_details_refresh',start_time, end_time,record_count);
			 
END 
$$;


