--

CREATE PROCEDURE expanded_radet.proc_upsert_laboratorytest_labtest_sample_results_refresh()
    LANGUAGE plpgsql
    AS $$
DECLARE start_time TIMESTAMP;
DECLARE last_load_end_time TIMESTAMP;
DECLARE end_time TIMESTAMP;
DECLARE record_count bigint;

BEGIN

-- Fetch the last load end time
SELECT MAX(load_end_time) 
INTO last_load_end_time
FROM streaming_remote_monitoring
WHERE table_name = 'laboratorytest_labtest_sample_results_refresh';

-- Fetch record count from the remote database using dblink
EXECUTE FORMAT(
	'SELECT *
	 FROM dblink(''db_link_ods'',
	 ''
	 SELECT count(uuid) 
	 FROM ods_laboratory_test 
	 WHERE ods_load_time >= ''%L''			   
	'') 
	 AS sm(count bigint)',last_load_end_time) 
INTO record_count;

-- DROP TABLE expanded_radet.laboratorytest_labtest_sample_results_refresh;
CREATE TABLE IF NOT EXISTS expanded_radet.laboratorytest_labtest_sample_results_refresh
(	uuid character varying,
    lab_order_id integer,
    patient_uuid character varying,
    ods_datim_id character varying(255),
    test character varying,
    date_sample_collected date,
    result character varying,
    date_result_reported date,
    --indication character varying,
    archived integer,
 	load_end_time timestamp,
	CONSTRAINT unq_orderidpatientdatim_labtest_basecodeapp 
	UNIQUE (uuid,lab_order_id,patient_uuid, ods_datim_id)
);

CREATE INDEX IF NOT EXISTS idx_patientuuiddatim_labtest_basecodeapp ON 
expanded_radet.laboratorytest_labtest_sample_results_refresh(patient_uuid,ods_datim_id);

SELECT TIMEOFDAY() INTO start_time;

EXECUTE FORMAT ('INSERT INTO expanded_radet.laboratorytest_labtest_sample_results_refresh
SELECT * from dblink(''db_link_ods'',
''SELECT DISTINCT ON (lt.uuid,lt.lab_order_id,lt.patient_uuid,lt.ods_datim_id) lt.uuid,
lt.lab_order_id, lt.patient_uuid, lt.ods_datim_id,ll.lab_test_name AS test,
CAST(ls.date_sample_collected AS DATE) AS date_sample_collected,
lr.result_reported AS result,CAST(lr.date_result_reported AS DATE) AS date_result_reported,
lt.archived,lt.viral_load_indication, TIMEOFDAY() load_end_time
FROM (SELECT id,uuid,lab_order_id,lab_test_id,patient_uuid,ods_datim_id,viral_load_indication,archived
		FROM ods_laboratory_test WHERE ods_load_time >= ''%L'') lt
LEFT JOIN ods_laboratory_labtest ll ON ll.id = lt.lab_test_id AND ll.ods_datim_id = lt.ods_datim_id
LEFT JOIN ods_laboratory_sample ls ON ls.test_id = lt.id AND ls.patient_uuid = lt.patient_uuid AND ls.ods_datim_id=lt.ods_datim_id
LEFT JOIN ods_laboratory_result lr ON lr.test_id = lt.id AND lr.patient_uuid = lt.patient_uuid AND lr.ods_datim_id=lt.ods_datim_id
--LEFT JOIN ods_base_application_codeset bac_viral_load ON bac_viral_load.id = lt.viral_load_indication AND bac_viral_load.ods_datim_id=lt.ods_datim_id
WHERE ll.lab_test_name = ''''Viral Load''''
'')AS sm(uuid character varying, lab_order_id integer,patient_uuid character varying,
	ods_datim_id character varying(255),test character varying,date_sample_collected date,
	result character varying,date_result_reported date,archived integer,
	viral_load_indication integer, load_end_time timestamp)
				
ON CONFLICT(uuid,lab_order_id,patient_uuid, ods_datim_id)
DO UPDATE SET
	test=EXCLUDED.test,
	--indication=EXCLUDED.indication,
	date_sample_collected=EXCLUDED.date_sample_collected,
	result=EXCLUDED.result,
	date_result_reported=EXCLUDED.date_result_reported,
	archived=EXCLUDED.archived,
	viral_load_indication=EXCLUDED.viral_load_indication,
	load_end_time=EXCLUDED.load_end_time',
	last_load_end_time);

SELECT TIMEOFDAY() INTO end_time;

DELETE FROM expanded_radet.laboratorytest_labtest_sample_results_refresh
WHERE archived=1;

INSERT INTO public.streaming_remote_monitoring(table_name,start_time,load_end_time,record_count)
VALUES('laboratorytest_labtest_sample_results_refresh',start_time, end_time,record_count);

END 
$$;


ALTER PROCEDURE expanded_radet.proc_upsert_laboratorytest_labtest_sample_results_refresh() OWNER TO lamisplus_etl;

--
-- Name: proc_upsert_lastpickup_refresh(); Type: PROCEDURE; Schema: expanded_radet; Owner: lamisplus_etl
--

CREATE PROCEDURE expanded_radet.proc_upsert_lastpickup_refresh()
    LANGUAGE plpgsql
    AS $$
DECLARE 
		last_load_end_time TIMESTAMP;
		start_time TIMESTAMP;
		end_time TIMESTAMP;
BEGIN
-- DROP TABLE IF EXISTS expanded_radet.lastpickup_refresh;
CREATE TABLE IF NOT EXISTS expanded_radet.lastpickup_refresh
(
    person_uuid14 character varying,
	ods_datim_id  character varying,
	lastPickupDateBeforeUnsuppressedVLR date,
	monthOfARVRefillOfLastPickupDateBeforeUnsuppressedVLR numeric(10,1),
	row bigint,
	CONSTRAINT unq_personuuiddatimlastmonth_lastpickup
	UNIQUE (person_uuid14, ods_datim_id, lastPickupDateBeforeUnsuppressedVLR,monthOfARVRefillOfLastPickupDateBeforeUnsuppressedVLR,row)
);

CREATE INDEX IF NOT EXISTS row_lastpickup_refresh 
ON expanded_radet.lastpickup_refresh(row);

SELECT TIMEOFDAY() INTO start_time;

INSERT INTO expanded_radet.lastpickup_refresh
SELECT person_uuid40 person_uuid14,pharma_ods_datim_id ods_datim_id,
visit_date lastPickupDateBeforeUnsuppressedVLR,
CAST(refill_period /30.0 AS DECIMAL(10,1)) monthOfARVRefillOfLastPickupDateBeforeUnsuppressedVLR,
ROW_NUMBER() OVER (PARTITION BY person_uuid40,pharma_ods_datim_id
				   ORDER BY visit_date DESC) row
FROM expanded_radet.pharmacy_details_regimen
ON CONFLICT(person_uuid14, ods_datim_id, lastPickupDateBeforeUnsuppressedVLR,monthOfARVRefillOfLastPickupDateBeforeUnsuppressedVLR,row)
DO UPDATE SET
	row=EXCLUDED.row;

SELECT TIMEOFDAY() INTO end_time;

INSERT INTO public.streaming_remote_monitoring(table_name,start_time,load_end_time)
VALUES('lastpickup_refresh',start_time, end_time);
	
END 
$$;


ALTER PROCEDURE expanded_radet.proc_upsert_lastpickup_refresh() OWNER TO lamisplus_etl;

--
-- Name: proc_upsert_patient_bio_data(); Type: PROCEDURE; Schema: expanded_radet; Owner: lamisplus_etl
--

CREATE PROCEDURE expanded_radet.proc_upsert_patient_bio_data()
    LANGUAGE plpgsql
    AS $_$
DECLARE 
		last_load_end_time TIMESTAMP;
		start_time TIMESTAMP;
		end_time TIMESTAMP;
		record_count bigint;
BEGIN

-- Fetch the last load end time
SELECT MAX(load_end_time) 
INTO last_load_end_time
FROM streaming_remote_monitoring
WHERE table_name = 'patient_bio_data_refresh';

-- Fetch record count from the remote database using dblink
EXECUTE format(
	'SELECT *
	 FROM dblink(''db_link_ods'',
	 ''
	 SELECT count(uuid) 
	 FROM ods_patient_person 
	 WHERE ods_load_time >= ''%L''			   
	'') 
	 AS sm(count bigint)',last_load_end_time) 
INTO record_count;

-- Use a temporary table to capture the rows affected by the upsert
CREATE TEMP TABLE temp_upsert_patient_bio_data (
        personuuid character varying,
        bio_ods_datim_id character varying
    );
	
SELECT TIMEOFDAY() INTO start_time;

EXECUTE format('INSERT INTO expanded_radet.patient_bio_data
SELECT * FROM dblink(''db_link_ods'',
''SELECT DISTINCT ON (p.uuid, p.ods_datim_id) p.uuid AS personUuid,
p.ods_datim_id AS bio_ods_datim_id,''''******'''' AS hospitalNumber,
p.marital_status->>''''display'''' as maritalStatus,education->>''''display'''' as education, 
p.employment_status->>''''display'''' as occupation,p.address,p.stateId,p.lgaId,
res_state.name as residentialState,
res_lga AS residentialLga,h.unique_id AS uniqueId,
(CASE WHEN contact_point->''''contactPoint''''->0->>''''type''''=''''phone'''' 
THEN contact_point->''''contactPoint''''->0->>''''value'''' ELSE null END) AS phone,
INITCAP(p.sex) AS gender,p.date_of_birth AS dateOfBirth,facility.facility_name AS facilityName,
facility.facility_lga AS lga,facility.facility_state AS state, p.ods_datim_id AS datimId,
facility.ip_code,facility.ip_name,tgroup.display AS targetGroup,eSetting.display AS enrollmentSetting,
hac.visit_date AS artStartDate,hr.description AS regimenAtStart,p.date_of_registration AS dateOfRegistration,
h.date_of_registration AS dateOfEnrollment,h.ovc_number AS ovcUniqueId,h.house_hold_number AS householdUniqueNo,
ecareEntry.display AS entryPoint,hrt.description AS regimenLineAtStart,hac.is_commencement, 
hac.visit_date,p.archived ods_patient_person_archived,hac.archived AS ods_hiv_art_clinical_archived, 
h.archived AS ods_hiv_enrollment_archived,h.person_uuid AS ods_hiv_enrollment_person_uuid, 
hac.person_uuid AS ods_hiv_art_clinical_person_uuid,sar.display as statusAtRegistration,
h.date_confirmed_hiv as dateOfConfirmedHiv,h.date_started datestartedhivenrollment,
pmtctenroll.entry_point pmtctenroll_entrypoint,pmtctenroll.lmp pmtctenroll_lmp,
pmtctenroll.gravida pmtctenroll_gravida,pmtctenroll.hepatitisb pmtctenroll_hepatitisb,
pmtctenroll.art_start_date pmtctenroll_art_start_date, 
pmtctenroll.art_start_time pmtctenroll_art_start_time,
REPLACE(pmtctinfantinfo.sex,''''SEX_'''','''''''') pmtctinfantinfo_sex, 
pmtctinfantinfo.body_weight pmtctinfantinfo_body_weight,
pmtctinfantarv.infant_arv_time pmtctinfantarv_infant_art_time, 
pmtctinfantarv.infant_arv_type pmtctinfantarv_infant_art_type,
pmtctinfantarv.age_at_ctx pmtctinfantarv_age_at_ctx
FROM (select uuid,ods_datim_id,hospital_number,date_of_birth,sex,facility_id,
	date_of_registration,archived,marital_status,education,contact_point,employment_status,
	REPLACE(REPLACE(REPLACE(REPLACE(REPLACE(CAST(address_object->>''''line'''' AS text),
		''''"'''', ''''''''), '''']'''', ''''''''), ''''['''', ''''''''), ''''null'''',''''''''), ''''\\\\\\\'''', '''''''') AS address,
	CASE WHEN address_object->>''''stateId''''  ~ ''''^\\\\d(\\\\.\\\\d)?$'''' THEN address_object->>''''stateId'''' ELSE null END  AS stateId,
	CASE WHEN address_object->>''''district''''  ~ ''''^\\\\d(\\\\.\\\\d)?$'''' THEN address_object->>''''district'''' ELSE null END  AS lgaId
	FROM ods_patient_person pp 
	LEFT JOIN jsonb_array_elements(pp.address-> ''''address'''') as l(address_object) on true
	WHERE ods_load_time >= ''%L'')p
LEFT OUTER JOIN central_partner_mapping facility ON facility.facility_id = p.facility_id  AND facility.datim_id = p.ods_datim_id
LEFT JOIN ods_hiv_enrollment h ON h.person_uuid = p.uuid  AND h.ods_datim_id = p.ods_datim_id  --iNNER
LEFT OUTER JOIN ods_base_application_codeset tgroup ON tgroup.id = h.target_group_id AND tgroup.ods_datim_id = h.ods_datim_id
LEFT OUTER JOIN ods_base_application_codeset eSetting ON eSetting.id = h.enrollment_setting_id AND eSetting.ods_datim_id = h.ods_datim_id
LEFT OUTER JOIN ods_base_application_codeset ecareEntry ON ecareEntry.id = h.entry_point_id AND ecareEntry.ods_datim_id = h.ods_datim_id
LEFT JOIN ods_base_application_codeset sar ON sar.id=h.status_at_registration_id AND sar.ods_datim_id=h.ods_datim_id
LEFT JOIN ods_hiv_art_clinical hac ON hac.hiv_enrollment_uuid = h.uuid  AND hac.ods_datim_id = h.ods_datim_id AND hac.person_uuid=p.uuid
AND hac.is_commencement = TRUE  --iNNER
LEFT JOIN ods_hiv_regimen hr ON hr.id = hac.regimen_id  AND hr.ods_datim_id = hac.ods_datim_id  --INNER
LEFT OUTER JOIN ods_hiv_regimen_type hrt ON hrt.id = hac.regimen_type_id  AND hrt.ods_datim_id = hac.ods_datim_id
LEFT JOIN ods_base_organisation_unit res_state ON res_state.id=CAST(p.stateid AS BIGINT) and res_state.ods_datim_id=p.ods_datim_id
LEFT JOIN ods_base_organisation_unit res_lga ON res_lga.id=CAST(p.lgaid AS BIGINT) AND res_lga.ods_datim_id=p.ods_datim_id
left JOIN public.ods_pmtct_enrollment pmtctenroll ON pmtctenroll.person_uuid = p.uuid and pmtctenroll.ods_datim_id=p.ods_datim_id
left join public.ods_pmtct_infant_information pmtctinfantinfo on pmtctinfantinfo.mother_person_uuid = p.uuid and pmtctinfantinfo.ods_datim_id=p.ods_datim_id
left join public.ods_pmtct_infant_arv pmtctinfantarv on pmtctinfantarv.uuid = p.uuid and pmtctinfantarv.ods_datim_id=p.ods_datim_id
'')
AS sm(personuuid character varying,bio_ods_datim_id character varying(255),hospitalnumber character varying,
maritalstatus text,education text,occupation text,address text,stateid text,lgaid text,residentialState character varying,
residentialLga character varying, uniqueid character varying,phone text,gender text,dateofbirth date,
facilityname character varying(255),lga character varying(255),state character varying(255),datimid character varying(255),
ip_code bigint,ip_name character varying(255),targetgroup character varying,enrollmentsetting character varying,
artstartdate date,regimenatstart character varying,dateofregistration date,dateofenrollment date,
ovcuniqueid character varying,householduniqueno character varying,entryPoint character varying,
regimenlineatstart character varying,is_commencement boolean,visit_date date,
ods_patient_person_archived integer,ods_hiv_art_clinical_archived integer,ods_hiv_enrollment_archived integer,
ods_hiv_enrollment_person_uuid character varying,ods_hiv_art_clinical_person_uuid character varying,
statusAtRegistration character varying,dateOfConfirmedHiv date,datestartedhivenrollment date,
pmtctenroll_entrypoint character varying, pmtctenroll_lmp date, pmtctenroll_gravida integer, 
pmtctenroll_hepatitisb character varying, pmtctenroll_art_start_date date, 
pmtctenroll_art_start_time character varying, pmtctinfantinfo_sex character varying,
pmtctinfantinfo_body_weight double precision, pmtctinfantarv_infant_art_time character varying,
pmtctinfantarv_infant_art_type character varying, pmtctinfantarv_age_at_ctx character varying
)
ON CONFLICT (personUuid,bio_ods_datim_id)
DO  UPDATE SET     
	statusAtRegistration=EXCLUDED.statusAtRegistration,
	maritalstatus=EXCLUDED.maritalstatus,
	education=EXCLUDED.education,
	residentialState=EXCLUDED.residentialState,
	residentialLga=EXCLUDED.residentialLga,
	occupation=EXCLUDED.occupation,
	address=EXCLUDED.address,
	stateid=EXCLUDED.stateid,
	lgaid=EXCLUDED.lgaid,
	phone=EXCLUDED.phone,
	hospitalnumber = EXCLUDED.hospitalnumber,
    uniqueid = EXCLUDED.uniqueid,
    gender = EXCLUDED.gender,
    dateofbirth = EXCLUDED.dateofbirth,
    facilityname = EXCLUDED.facilityname,
    lga = EXCLUDED.lga,
    state = EXCLUDED.state,
    datimid = EXCLUDED.datimid,
    ip_code = EXCLUDED.ip_code,
    ip_name = EXCLUDED.ip_name,
    targetgroup = EXCLUDED.targetgroup,
    enrollmentsetting = EXCLUDED.enrollmentsetting,
    artstartdate = EXCLUDED.artstartdate,
    regimenatstart = EXCLUDED.regimenatstart,
    dateofregistration = EXCLUDED.dateofregistration,
    dateofenrollment = EXCLUDED.dateofenrollment,
    ovcuniqueid = EXCLUDED.ovcuniqueid,
    householduniqueno = EXCLUDED.householduniqueno,
	dateOfConfirmedHiv=EXCLUDED.dateOfConfirmedHiv,
	datestartedhivenrollment=EXCLUDED.datestartedhivenrollment,
    entryPoint = EXCLUDED.entryPoint,
    regimenlineatstart = EXCLUDED.regimenlineatstart,
    is_commencement = EXCLUDED.is_commencement,
    visit_date = EXCLUDED.visit_date,
	pmtctenroll_entrypoint = EXCLUDED.pmtctenroll_entrypoint, 
	pmtctenroll_lmp = EXCLUDED.pmtctenroll_lmp, 
	pmtctenroll_gravida = EXCLUDED.pmtctenroll_gravida, 
	pmtctenroll_hepatitisb = EXCLUDED.pmtctenroll_hepatitisb, 
	pmtctenroll_art_start_date = EXCLUDED.pmtctenroll_art_start_date, 
	pmtctenroll_art_start_time = EXCLUDED.pmtctenroll_art_start_time, 
	pmtctinfantinfo_sex = EXCLUDED.pmtctinfantinfo_sex,
	pmtctinfantinfo_body_weight = EXCLUDED.pmtctinfantinfo_body_weight, 
	pmtctinfantarv_infant_art_time = EXCLUDED.pmtctinfantarv_infant_art_time,
	pmtctinfantarv_infant_art_type = EXCLUDED.pmtctinfantarv_infant_art_type,
	pmtctinfantarv_age_at_ctx = EXCLUDED.pmtctinfantarv_age_at_ctx,
    ods_hiv_art_clinical_archived = EXCLUDED.ods_hiv_art_clinical_archived,
    ods_hiv_enrollment_archived = EXCLUDED.ods_hiv_enrollment_archived,
    ods_hiv_enrollment_person_uuid = EXCLUDED.ods_hiv_enrollment_person_uuid,
    ods_hiv_art_clinical_person_uuid = EXCLUDED.ods_hiv_art_clinical_person_uuid,
	ods_patient_person_archived=EXCLUDED.ods_patient_person_archived',
	last_load_end_time);

SELECT TIMEOFDAY() INTO end_time;

DELETE FROM expanded_radet.patient_bio_data
WHERE ods_patient_person_archived=1;

-- Count the number of rows inserted and updated
-- SELECT COUNT(personuuid) INTO inserted_count
-- FROM temp_upsert_patient_bio_data
-- WHERE NOT EXISTS (
-- 	SELECT 1
-- 	FROM expanded_radet.patient_bio_data t
-- 	WHERE t.personuuid = temp_upsert_patient_bio_data.personuuid
-- 	AND t.bio_ods_datim_id = temp_upsert_patient_bio_data.bio_ods_datim_id
-- );

-- SELECT COUNT(personuuid) INTO updated_count
-- FROM temp_upsert_patient_bio_data
-- WHERE EXISTS (
-- 	SELECT 1
-- 	FROM expanded_radet.patient_bio_data t
-- 	WHERE t.personuuid = temp_upsert_patient_bio_data.personuuid
-- 	AND t.bio_ods_datim_id = temp_upsert_patient_bio_data.bio_ods_datim_id
-- );

INSERT INTO public.streaming_remote_monitoring(table_name,start_time,load_end_time,record_count)
VALUES('patient_bio_data_refresh',start_time, end_time,record_count);
			 
END 
$_$;


ALTER PROCEDURE expanded_radet.proc_upsert_patient_bio_data() OWNER TO lamisplus_etl;

--
-- Name: proc_upsert_pharmacy_details_regimen(); Type: PROCEDURE; Schema: expanded_radet; Owner: lamisplus_etl
--

CREATE PROCEDURE expanded_radet.proc_upsert_pharmacy_details_regimen()
    LANGUAGE plpgsql
    AS $$
DECLARE 
		last_load_end_time TIMESTAMP;
		start_time TIMESTAMP;
		end_time TIMESTAMP;
		record_count bigint;
-- 		inserted_count bigint;
-- 		updated_count bigint;

BEGIN
-- Fetch the last load end time
SELECT MAX(load_end_time) 
INTO last_load_end_time
FROM streaming_remote_monitoring
WHERE table_name = 'pharmacy_details_regimen_refresh';

-- Fetch record count from the remote database using dblink
EXECUTE format(
	'SELECT *
	 FROM dblink(''db_link_ods'',
	 ''
	 SELECT count(uuid) 
	 FROM ods_hiv_art_pharmacy 
	 WHERE ods_load_time >= ''%L''			   
	'') 
	 AS sm(count bigint)',last_load_end_time) 
INTO record_count;

-- -- Use a temporary table to capture the rows affected by the upsert
-- CREATE TEMP TABLE temp_upsert_pharmacy_details_regimen (
-- 		uuid character varying,
--         person_uuid40 character varying,
--         pharma_ods_datim_id character varying
--     );

SELECT TIMEOFDAY() INTO start_time;

EXECUTE FORMAT('INSERT INTO expanded_radet.pharmacy_details_regimen
SELECT * from dblink(''db_link_ods'',
''SELECT DISTINCT ON (p.uuid,p.ods_datim_id) p.uuid, p.person_uuid AS person_uuid40,
p.ods_datim_id as pharma_ods_datim_id,COALESCE(ds_model.display, p.dsd_model_type) as dsdModel, 
p.visit_date,r.description as ods_hiv_regimen_description, 
rt.description as ods_hiv_regimen_type_description ,p.next_appointment, r.regimen_type_id,
p.refill_period,p.archived, TIMEOFDAY() AS phar_details_regimen_load_time,
p.mmd_type,''''******'''' AS hospital_number, 
cpm.facility_name facility,cpm.facility_state state, cpm.facility_lga lga,
he.person_uuid hiv_enrollment_uuid
from (SELECT id,uuid,person_uuid,ods_datim_id,dsd_model_type,archived,
				 visit_date,refill_period,next_appointment,mmd_type
	FROM public.ods_hiv_art_pharmacy 
WHERE ods_load_time >= ''%L'') p 
--LEFT JOIN public.ods_patient_person opp ON opp.ods_datim_id=p.ods_datim_id AND opp.uuid=p.person_uuid
LEFT JOIN public.ods_hiv_enrollment he ON he.person_uuid=p.person_uuid AND he.ods_datim_id=p.ods_datim_id 
--AND he.archived=0
LEFT JOIN public.central_partner_mapping cpm ON cpm.datim_id=p.ods_datim_id
LEFT JOIN public.ods_hiv_art_pharmacy_regimens pr ON pr.art_pharmacy_id = p.id AND pr.ods_datim_id = p.ods_datim_id     --INNER 
LEFT JOIN public.ods_hiv_regimen r on r.id = pr.regimens_id AND r.ods_datim_id = pr.ods_datim_id						--INNER
LEFT JOIN public.ods_hiv_regimen_type rt on rt.id = r.regimen_type_id AND rt.ods_datim_id = r.ods_datim_id				--INNER
LEFT JOIN ods_base_application_codeset ds_model on ds_model.code = p.dsd_model_type  
AND ds_model.ods_datim_id = p.ods_datim_id'')
AS sm(uuid character varying, person_uuid40 character varying, pharma_ods_datim_id character varying,
dsdmodel character varying, visit_date date,ods_hiv_regimen_description character varying,
ods_hiv_regimen_type_description character varying, next_appointment date, regimen_type_id bigint,
refill_period integer,archived integer,phar_details_regimen_load_time timestamp,
mmd_type character varying, hospital_number character varying,
facility character varying, state character varying, lga character varying,
hiv_enrollment_uuid character varying)
ON CONFLICT(uuid, person_uuid40,pharma_ods_datim_id)
DO UPDATE SET
	archived=EXCLUDED.archived,
	dsdmodel=EXCLUDED.dsdmodel,
	visit_date=EXCLUDED.visit_date,
	ods_hiv_regimen_description=EXCLUDED.ods_hiv_regimen_description,
	ods_hiv_regimen_type_description=EXCLUDED.ods_hiv_regimen_type_description,
	next_appointment=EXCLUDED.next_appointment,
	regimen_type_id=EXCLUDED.regimen_type_id,
	refill_period=EXCLUDED.refill_period,
	mmd_type=EXCLUDED.mmd_type,
	hospital_number=EXCLUDED.hospital_number,
	facility=EXCLUDED.facility,
	state=EXCLUDED.state,
	lga=EXCLUDED.lga
',last_load_end_time);

-- 		RETURNING uuid, person_uuid40,pharma_ods_datim_id 
-- 		INTO temp_upsert_pharmacy_details_regimen
		
SELECT TIMEOFDAY() INTO end_time;

DELETE FROM expanded_radet.pharmacy_details_regimen
WHERE archived=1;

-- -- Count the number of rows inserted and updated
-- SELECT COUNT(person_uuid40) INTO inserted_count
-- FROM temp_upsert_pharmacy_details_regimen
-- WHERE NOT EXISTS (
-- 	SELECT 1
-- 	FROM expanded_radet.pharmacy_details_regimen t
-- 	WHERE t.uuid = temp_upsert_pharmacy_details_regimen.uuid
-- 	AND t.pharma_ods_datim_id = temp_upsert_pharmacy_details_regimen.pharma_ods_datim_id
-- 	AND t.person_uuid40=temp_upsert_pharmacy_details_regimen.person_uuid40
-- );

-- SELECT COUNT(person_uuid40) INTO updated_count
-- FROM temp_upsert_pharmacy_details_regimen
-- WHERE EXISTS (
-- 	SELECT 1
-- 	FROM expanded_radet.pharmacy_details_regimen t
-- 	WHERE t.uuid = temp_upsert_pharmacy_details_regimen.uuid
-- 	AND t.pharma_ods_datim_id = temp_upsert_pharmacy_details_regimen.pharma_ods_datim_id
-- 	AND t.person_uuid40=temp_upsert_pharmacy_details_regimen.person_uuid40
-- );

INSERT INTO public.streaming_remote_monitoring(table_name,start_time,load_end_time,
											   --inserted_count,updated_count,
											   record_count)
VALUES('pharmacy_details_regimen_refresh',start_time, end_time,
	   --inserted_count, updated_count, 
	   record_count);
	
END 
$$;


