--
-- Name: proc_upsert_regimenatstart_refresh(); Type: PROCEDURE; Schema: expanded_radet; Owner: lamisplus_etl
--

CREATE PROCEDURE expanded_radet.proc_upsert_regimenatstart_refresh()
    LANGUAGE plpgsql
    AS $$
DECLARE 
		last_load_end_time TIMESTAMP;
		start_time TIMESTAMP;
		end_time TIMESTAMP;
BEGIN
-- DROP TABLE IF EXISTS expanded_radet.regimenatstart_refresh;
CREATE TABLE IF NOT EXISTS expanded_radet.regimenatstart_refresh
(
    person_uuid40 character varying,
    pharma_ods_datim_id character varying,
    ods_hiv_regimen_description character varying,
	ods_hiv_regimen_type_description character varying,
    min_visit_date date,
    row bigint,
	CONSTRAINT unq_personuuiddatimregimen_regimenatstart
	UNIQUE (person_uuid40, pharma_ods_datim_id, ods_hiv_regimen_description,min_visit_date,row)
);

CREATE INDEX IF NOT EXISTS row_regimenatstart_refresh 
ON expanded_radet.regimenatstart_refresh(row);


SELECT TIMEOFDAY() INTO start_time;

INSERT INTO expanded_radet.regimenatstart_refresh
SELECT pdr.person_uuid40, pdr.pharma_ods_datim_id, 
pdr.ods_hiv_regimen_description,pdr.ods_hiv_regimen_type_description,
min.min_visit_date,
ROW_NUMBER() OVER (PARTITION BY pdr.person_uuid40, pdr.pharma_ods_datim_id 
				   ORDER BY min.min_visit_date DESC) AS row
FROM expanded_radet.pharmacy_details_regimen pdr
INNER JOIN (SELECT person_uuid40, pharma_ods_datim_id, ods_hiv_regimen_description,
MIN(visit_date)min_visit_date
FROM expanded_radet.pharmacy_details_regimen
where regimen_type_id in (1,2,3,4,14)
GROUP BY 1,2,3) min 
on min.min_visit_date = pdr.visit_date AND min.person_uuid40=pdr.person_uuid40 
AND min.pharma_ods_datim_id=pdr.pharma_ods_datim_id
WHERE regimen_type_id in (1,2,3,4,14)
ON CONFLICT(person_uuid40, pharma_ods_datim_id,ods_hiv_regimen_description,min_visit_date,row)
DO UPDATE SET
	row=EXCLUDED.row;


SELECT TIMEOFDAY() INTO end_time;

INSERT INTO public.streaming_remote_monitoring(table_name,start_time,load_end_time)
VALUES('regimenatstart_refresh',start_time, end_time);
	
END 
$$;


ALTER PROCEDURE expanded_radet.proc_upsert_regimenatstart_refresh() OWNER TO lamisplus_etl;

