-- Name: proc_upsert_sub_laboratory_details_refresh(); Type: PROCEDURE; Schema: expanded_radet; Owner: lamisplus_etl
--

CREATE PROCEDURE expanded_radet.proc_upsert_sub_laboratory_details_refresh()
    LANGUAGE plpgsql
    AS $$
DECLARE start_time TIMESTAMP;
DECLARE last_load_end_time TIMESTAMP;
DECLARE end_time TIMESTAMP;
DECLARE record_count bigint;

BEGIN

-- Fetch the last load end time
SELECT MAX(load_end_time) 
INTO last_load_end_time
FROM streaming_remote_monitoring
WHERE table_name = 'sub_laboratory_details_refresh';

-- Fetch record count from the remote database using dblink
SELECT count(patient_uuid) 
	 FROM expanded_radet.laboratorytest_labtest_sample_results_refresh
	 WHERE load_end_time > last_load_end_time
INTO record_count;

CREATE TABLE IF NOT EXISTS expanded_radet.sub_laboratory_details_refresh
(
    uuid character varying,
    lab_order_id integer,
    patient_uuid character varying,
    ods_datim_id character varying(255),
    test character varying,
    date_sample_collected date,
    result character varying,
    date_result_reported date,
    archived integer,
    viral_load_indication integer,
    indication character varying,
	CONSTRAINT unq_uuidorderidpatientdatimlabtestresults_basecodeapp 
	UNIQUE (uuid,lab_order_id,patient_uuid, ods_datim_id)
);

CREATE INDEX IF NOT EXISTS idx_loidpuuiddatim_sublaboratorydetailsrefresh ON 
expanded_radet.sub_laboratory_details_refresh(lab_order_id,patient_uuid,ods_datim_id);

SELECT TIMEOFDAY() INTO start_time;

INSERT INTO expanded_radet.sub_laboratory_details_refresh
SELECT DISTINCT ON(ltlsr.uuid,ltlsr.lab_order_id,ltlsr.patient_uuid,ltlsr.ods_datim_id) ltlsr.uuid,
			   ltlsr.lab_order_id,ltlsr.patient_uuid,ltlsr.ods_datim_id,
			   ltlsr.test,ltlsr.date_sample_collected,ltlsr.result,ltlsr.date_result_reported,
			   ltlsr.archived,ltlsr.viral_load_indication,bac.display indication
FROM (SELECT * FROM 
	  expanded_radet.laboratorytest_labtest_sample_results_refresh
	  WHERE load_end_time >  last_load_end_time) ltlsr
LEFT JOIN expanded_radet.baseappcodeset_refresh bac
ON ltlsr.viral_load_indication=bac.id AND ltlsr.ods_datim_id=bac.ods_datim_id
ON CONFLICT(uuid,lab_order_id,patient_uuid, ods_datim_id)
DO UPDATE SET
	test=EXCLUDED.test,
	indication=EXCLUDED.indication,
	date_sample_collected=EXCLUDED.date_sample_collected,
	result=EXCLUDED.result,
	date_result_reported=EXCLUDED.date_result_reported;

SELECT TIMEOFDAY() INTO end_time;

INSERT INTO public.streaming_remote_monitoring(table_name,start_time,load_end_time,record_count)
VALUES('sub_laboratory_details_refresh',start_time, end_time,record_count);
			 
END 
$$;


