--

CREATE PROCEDURE expanded_radet.proc_upsert_sub_tvs_current_clinical_refresh()
    LANGUAGE plpgsql
    AS $$
DECLARE start_time TIMESTAMP;
DECLARE last_load_end_time TIMESTAMP;
DECLARE end_time TIMESTAMP;
DECLARE record_count bigint;

BEGIN

-- Fetch the last load end time
SELECT MAX(load_end_time) 
INTO last_load_end_time
FROM streaming_remote_monitoring
WHERE table_name = 'sub_tvs_current_clinical_refresh';

-- Fetch record count from the remote database using dblink
EXECUTE FORMAT(
	'SELECT *
	 FROM dblink(''db_link_ods'',
	 ''
	 SELECT count(uuid) 
	 FROM ods_triage_vital_sign 
	 WHERE ods_load_time >= ''%L''			   
	'') 
	 AS sm(count bigint)',last_load_end_time) 
INTO record_count;

SELECT TIMEOFDAY() INTO start_time;
INSERT INTO expanded_radet.sub_tvs_current_clinical_refresh
(person_uuid10,clin_ods_datim_id,capture_date,currentWeight,tbstatus1,
 currentclinicalstage,pregnancystatus,dateoftbscreened1,tvs_archived
)
SELECT DISTINCT ON (tvs.person_uuid,tvs.ods_datim_id) tvs.person_uuid AS person_uuid10,
   tvs.ods_datim_id AS clin_ods_datim_id,
    CAST(tvs.capture_date AS DATE) AS capture_date,tvs.body_weight AS currentWeight,
    hac.tbstatus1,hac.currentclinicalstage,hac.pregnancystatus,hac.dateoftbscreened1,
    tvs.archived tvs_archived
FROM (SELECT * FROM dblink('db_link_ods',
       FORMAT('SELECT  uuid, person_uuid, ods_datim_id, capture_date, body_weight, archived 
			   FROM ods_triage_vital_sign 
			   WHERE ods_load_time > %L
			  ',last_load_end_time))
AS sm (uuid character varying,person_uuid character varying,ods_datim_id character varying,
        capture_date date,body_weight double precision,archived integer)
) AS tvs
INNER JOIN expanded_radet.hivclinicalenrollment_baseappcode_refresh hac
ON tvs.uuid = hac.vital_sign_uuid AND tvs.ods_datim_id = hac.ods_datim_id
ON CONFLICT(person_uuid10,clin_ods_datim_id,capture_date)
DO UPDATE SET
capture_date=EXCLUDED.capture_date,
currentWeight=EXCLUDED.currentWeight,
tbstatus1=EXCLUDED.tbstatus1,
currentclinicalstage=EXCLUDED.currentclinicalstage,
pregnancystatus=EXCLUDED.pregnancystatus,
dateoftbscreened1=EXCLUDED.dateoftbscreened1,
tvs_archived=EXCLUDED.tvs_archived;

SELECT TIMEOFDAY() INTO end_time;

DELETE FROM expanded_radet.sub_tvs_current_clinical_refresh
WHERE tvs_archived=1;

INSERT INTO public.streaming_remote_monitoring(table_name,start_time,load_end_time,record_count)
VALUES('sub_tvs_current_clinical_refresh',start_time, end_time,record_count);
			 
END 
$$;


