--
-- Name: process_lab_test(text, timestamp without time zone); Type: FUNCTION; Schema: expanded_radet; Owner: lamisplus_etl
--

CREATE FUNCTION expanded_radet.process_lab_test(lab_test text, last_load_end_time timestamp without time zone) RETURNS void
    LANGUAGE plpgsql
    AS $$
DECLARE
    lab_test_id BIGINT;
    partitioned_name TEXT;
    constraint_check TEXT;
BEGIN
    -- Fetch the lab_test_id for the current lab_test
    SELECT id 
	INTO lab_test_id
    FROM public.lab_test_name
    WHERE lab_test_name = lab_test;

    SELECT partition_name 
	INTO partitioned_name
    FROM public.lab_test_name
    WHERE lab_test_name = lab_test;

    SELECT CONCAT(partition_name, '_check') 
	INTO constraint_check
    FROM public.lab_test_name
    WHERE lab_test_name = lab_test;

    EXECUTE FORMAT(
        'CREATE TABLE IF NOT EXISTS expanded_radet.%I
         PARTITION OF expanded_radet.lab_test_results_refresh
         FOR VALUES IN (%L)', partitioned_name, lab_test);

--     EXECUTE FORMAT(
--         'ALTER TABLE expanded_radet.%I
--          ADD CONSTRAINT IF NOT EXISTS %I CHECK (test=%L)', 
--         partitioned_name, constraint_check, lab_test);
-- expanded_radet.lab_test_results_refresh
    EXECUTE FORMAT(
        'INSERT INTO expanded_radet.%I
        SELECT * FROM dblink(''db_link_ods'',
        ''SELECT DISTINCT ON (lt.id, lt.ods_datim_id) lt.id, lt.uuid,
        lt.lab_order_id, lt.patient_uuid, lt.ods_datim_id, ''%L'' AS test,
        CAST(ls.date_sample_collected AS DATE) AS date_sample_collected,
        lr.result_reported AS result, CAST(lr.date_result_reported AS DATE) AS date_result_reported,
        lt.archived, lt.viral_load_indication, TIMEOFDAY() load_end_time
        FROM (SELECT id, uuid, lab_order_id, lab_test_id, patient_uuid, ods_datim_id,
              viral_load_indication, archived 
              FROM ods_laboratory_test WHERE ods_load_time >= ''%L'' 
              AND lab_test_id = ''%L'' AND lab_test_id IS NOT NULL AND archived = 0
			  AND ods_datim_id IN (SELECT distinct ods_datim_id
								   FROM ods_laboratory_labtest 
								   WHERE id IS NOT NULL AND lab_test_name = ''%L'')) lt
        LEFT JOIN (SELECT id, ods_datim_id, lab_test_name 
                   FROM ods_laboratory_labtest 
					WHERE id = ''%L'' AND lab_test_name = ''%L'') ll 
        ON ll.id = lt.lab_test_id AND ll.ods_datim_id = lt.ods_datim_id
        LEFT JOIN ods_laboratory_sample ls ON ls.test_id = lt.id AND ls.patient_uuid = lt.patient_uuid 
        AND ls.ods_datim_id = lt.ods_datim_id AND ls.archived = 0
        LEFT JOIN ods_laboratory_result lr ON lr.test_id = lt.id AND lr.patient_uuid = lt.patient_uuid 
        AND lr.ods_datim_id = lt.ods_datim_id AND lr.archived = 0
        '') AS sm(id BIGINT, uuid CHARACTER VARYING, lab_order_id INTEGER, patient_uuid CHARACTER VARYING,
        ods_datim_id CHARACTER VARYING(255), test CHARACTER VARYING, date_sample_collected DATE,
        result CHARACTER VARYING, date_result_reported DATE, archived INTEGER,
        viral_load_indication INTEGER, load_end_time TIMESTAMP)
        ON CONFLICT(id, ods_datim_id, test)
        DO UPDATE SET
        test = EXCLUDED.test,
        date_sample_collected = EXCLUDED.date_sample_collected,
        result = EXCLUDED.result,
        date_result_reported = EXCLUDED.date_result_reported,
        archived = EXCLUDED.archived,
        viral_load_indication = EXCLUDED.viral_load_indication,
        load_end_time = EXCLUDED.load_end_time',
        partitioned_name,lab_test,last_load_end_time, lab_test_id, lab_test,lab_test_id,lab_test);
    
	-- Print the lab_test_id
    RAISE NOTICE 'new records for % successfully streamed', lab_test;
		
    -- Commit transaction for the current lab test
    PERFORM pg_advisory_xact_lock(lab_test_id);
END;
$$;


ALTER FUNCTION expanded_radet.process_lab_test(lab_test text, last_load_end_time timestamp without time zone) OWNER TO lamisplus_etl;

--
-- Name: update_aggregate_flatfile_weekly(); Type: PROCEDURE; Schema: expanded_radet; Owner: lamisplus_etl
--

CREATE PROCEDURE expanded_radet.update_aggregate_flatfile_weekly()
    LANGUAGE plpgsql
    AS $$BEGIN

CREATE INDEX IF NOT EXISTS idx_expanddradet_period
ON expanded_radet.period(periodid);
CREATE INDEX IF NOT EXISTS idx_aggregateflatfileweekly_period
ON expanded_radet.aggregate_flatfile_weekly(period);
UPDATE expanded_radet.aggregate_flatfile_weekly aff 
SET date=p.date 
FROM expanded_radet.aggregate_flatfile_weekly af 
INNER JOIN expanded_radet.period p on p.periodid=af.period
WHERE af.period='2024W36';

END$$;


