--
-- Name: generate_weekly_count_ods_tables(text, text, text); Type: FUNCTION; Schema: public; Owner: lamisplus_etl
--

CREATE FUNCTION public.generate_weekly_count_ods_tables(ods_table_name text, frontend_table_name text, constraint_column text) RETURNS void
    LANGUAGE plpgsql
    AS $$
DECLARE
    ods_table TEXT;
	load_time timestamp;
	period_start date;
	period_end_date date;
	period_end date;
	
	period_text character varying;

BEGIN
	
	SELECT CAST('1980-01-01' AS DATE) 
	INTO period_start;
	
-- 	SELECT date 
-- 	INTO period_end_date
-- 	FROM expanded_radet.period WHERE is_active;

	SELECT date 
	INTO period_end_date
	FROM expanded_radet.period 
	WHERE periodcode IN ('2024W42');
	
	
-- 	end date of current period didn't work
-- 	SELECT date + INTERVAL '2 day' AS date 
-- 	INTO period_end
-- 	FROM expanded_radet.period WHERE is_active;
	
	SELECT CURRENT_DATE
	INTO period_end;
	
	SELECT periodcode 
	INTO period_text
	FROM expanded_radet.period 
	WHERE periodcode IN ('2024W42');
-- 	FROM expanded_radet.period WHERE is_active;

-- 	SELECT TIMEOFDAY() INTO load_time;
	
    EXECUTE FORMAT(
	'INSERT INTO public.ods_count_monitoring(
	ip_name,ods_datim_id, table_name,period,period_end_date,
	current_total_records)
	SELECT ip_name,
		ods_datim_id, table_name,period,%L period_end_date,
	current_total_records
	FROM dblink(''db_link_ods'',
	''
	SELECT t2.ip_name, 
		t1.ods_datim_id,''%L'' table_name,''%L'' period,
	''%L'' period_end, COUNT(DISTINCT %s) AS current_total_records
	FROM %s t1
	LEFT JOIN central_partner_mapping t2 on t1.ods_datim_id=t2.datim_id
	WHERE t1.ods_load_time BETWEEN ''%L'' AND ''%L''
	GROUP BY 1,2,3,4,5
	'')
	AS sm(
		ip_name character varying,
		ods_datim_id character varying,table_name character varying,
		 period character varying,period_end date,current_total_records bigint)',
		period_end_date,frontend_table_name,period_text,period_end,constraint_column,
		ods_table_name,period_start, period_end);

	-- Print the ods_table_name
    RAISE NOTICE 'datim aggregated count for % successfully inserted', ods_table_name;
		
    -- Commit transaction for the current lab test
    PERFORM pg_advisory_xact_lock(hashtext(ods_table_name));
END;
$$;


ALTER FUNCTION public.generate_weekly_count_ods_tables(ods_table_name text, frontend_table_name text, constraint_column text) OWNER TO lamisplus_etl;

--
-- Name: proc_loop_through_lists(); Type: PROCEDURE; Schema: public; Owner: lamisplus_etl
--

CREATE PROCEDURE public.proc_loop_through_lists()
    LANGUAGE plpgsql
    AS $$
DECLARE
    inputs text[];
    input text;
    partition_name text;
BEGIN
    -- Populate the array with values from the existing table
--     SELECT array_agg(DISTINCT ip_name)
--     INTO inputs
--     FROM public.central_partner_mapping;
	SELECT array_agg(DISTINCT periodcode)
	INTO inputs
	FROM expanded_radet.period;



    -- Loop through each input value and execute the dynamic query
    FOREACH input IN ARRAY inputs
    LOOP
        partition_name := CONCAT('ods_count_',input);
        
		EXECUTE format('
            DROP TABLE IF EXISTS public.%I 
           ', partition_name);
			
        -- Loop through and create partitions
        EXECUTE format('
            CREATE TABLE IF NOT EXISTS public.%I 
            PARTITION OF public.ods_count_monitoring_backup
            FOR VALUES IN (%L)', partition_name, input);
    END LOOP;
END;
$$;


ALTER PROCEDURE public.proc_loop_through_lists() OWNER TO lamisplus_etl;

--
-- Name: proc_loop_through_ods_tables(); Type: PROCEDURE; Schema: public; Owner: lamisplus_etl
--

CREATE PROCEDURE public.proc_loop_through_ods_tables()
    LANGUAGE plpgsql
    AS $$
DECLARE
    inputs text[];
    input text;
    frontend_table_name text;
	constraint_column text;
	ods_table text;
	
BEGIN
    -- Populate the array with values from the existing table
    SELECT array_agg(ods_table_info)
    INTO inputs
    FROM public.ods_tables;
	
	-- Populate the array with value from the existing test table
-- 	SELECT array_agg(ods_table_info)
--     INTO inputs
-- 	FROM public.test_ods_tables;

    -- Loop through each input value and execute the dynamic query
    FOREACH input IN ARRAY inputs
    LOOP
        frontend_table_name := REPLACE(split_part(input, '-', 1),'ods_','');
		ods_table := split_part(input, '-', 1);
		constraint_column := split_part(input, '-', 2);

        -- Call the function to process each lab test
        PERFORM public.generate_weekly_count_ods_tables(ods_table,frontend_table_name,
														constraint_column);

    END LOOP;
END;
$$;


ALTER PROCEDURE public.proc_loop_through_ods_tables() OWNER TO lamisplus_etl;

--
-- Name: proc_stream_aggregate_flatfile(); Type: PROCEDURE; Schema: public; Owner: lamisplus_etl
--

CREATE PROCEDURE public.proc_stream_aggregate_flatfile()
    LANGUAGE plpgsql
    AS $$
DECLARE start_time TIMESTAMP;
DECLARE end_time TIMESTAMP;
DECLARE partition_name TEXT;
DECLARE periodtxt TEXT;

BEGIN


SELECT CONCAT('aggregate_flatfile_',periodcode) 
INTO partition_name
from expanded_radet.period where is_active;

SELECT periodcode
INTO periodtxt
from expanded_radet.period where is_active;


SELECT TIMEOFDAY() INTO start_time;

EXECUTE format('TRUNCATE public.%I',partition_name);

EXECUTE format('
INSERT INTO public.aggregate_flatfile(
	datim_id, period, data_element, data_element_name, 
	category_option_combo, category_option_combo_name, 
	attribute_option_combo, value, date
)
SELECT * FROM dblink(''db_link_ods'',
''SELECT datim_id, period, data_element, data_element_name,
category_option_combo, category_option_combo_name, 
attribute_option_combo, value, date
FROM public.aggregate_flatfile
WHERE period=''%L''
'') AS sm(datim_id character varying, period character varying, data_element character varying, 
		 data_element_name character varying,category_option_combo character varying, 
		 category_option_combo_name character varying,attribute_option_combo character varying, 
		 value integer, date date)',periodtxt);

UPDATE public.aggregate_flatfile aggfw
SET ip_name=cpm.ip_name, 
facility_name=cpm.facility_name,
facility_state=cpm.facility_state, 
facility_lga=cpm.facility_lga
FROM public.central_partner_mapping cpm
WHERE cpm.datim_id=aggfw.datim_id
AND aggfw.ip_name IS NULL
;

UPDATE public.aggregate_flatfile af
SET date=p.date
FROM public.period p
WHERE p.periodcode=af.period
AND af.date is null;

SELECT TIMEOFDAY() INTO end_time;
INSERT INTO expanded_radet.expanded_radet_monitoring (table_name, start_time,end_time) 
VALUES ('aggregate_flatfile', start_time,end_time);
		 
END 
$$;


ALTER PROCEDURE public.proc_stream_aggregate_flatfile() OWNER TO lamisplus_etl;

